INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (1, 'MATH SKILLS', 'Arithmetic Fundamentals', 'PEMDAS, fractions, decimals, percentages, and ratios', ARRAY['PEMDAS','Fractions','Percentages'], '<h1>Arithmetic Fundamentals</h1>
      <p class="lesson-subtitle">Master the building blocks of OAR math: order of operations, fractions, decimals, percentages, and ratios.</p>

      <h2>Order of Operations (PEMDAS)</h2>
      <p>Every math question on the OAR follows <strong>PEMDAS</strong> strictly. Violate it and you will get the wrong answer every single time.</p>
      <div class="callout callout-formula">
        <div class="callout-title">The Rule</div>
        <strong>P</strong>arentheses → <strong>E</strong>xponents → <strong>M</strong>ultiplication/<strong>D</strong>ivision (left to right) → <strong>A</strong>ddition/<strong>S</strong>ubtraction (left to right)
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">8 + 3 × 4 - 2</span><br>
        Step 1: Multiplication first → 3 × 4 = 12<br>
        Step 2: Left to right → 8 + 12 - 2 = <strong>18</strong>
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Common Trap</div>
        Students often add 8 + 3 first to get 11, then multiply. <strong>Always</strong> do multiplication and division before addition and subtraction.
      </div>

      <h2>Fractions</h2>
      <p>Fractions appear constantly on the OAR. You need to add, subtract, multiply, and divide them quickly and accurately.</p>

      <h3>Adding &amp; Subtracting Fractions</h3>
      <p>You must find a <strong>common denominator</strong>. The universal formula:</p>
      <div class="formula-block">\\\\[\\\\frac{a}{b} + \\\\frac{c}{d} = \\\\frac{ad + bc}{bd}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        \\\\(\\\\frac{3}{4} + \\\\frac{2}{3}\\\\)<br>
        \\\\(= \\\\frac{3 \\\\times 3 + 4 \\\\times 2}{4 \\\\times 3}\\\\)<br>
        \\\\(= \\\\frac{9 + 8}{12} = \\\\) <strong>\\\\(\\\\frac{17}{12}\\\\)</strong>
      </div>

      <h3>Multiplying Fractions</h3>
      <p>Straight across &mdash; no common denominator needed.</p>
      <div class="formula-block">\\\\[\\\\frac{a}{b} \\\\times \\\\frac{c}{d} = \\\\frac{ac}{bd}\\\\]</div>

      <h3>Dividing Fractions</h3>
      <p><strong>Flip</strong> the second fraction (take its reciprocal) and <strong>multiply</strong>.</p>
      <div class="formula-block">\\\\[\\\\frac{a}{b} \\\\div \\\\frac{c}{d} = \\\\frac{a}{b} \\\\times \\\\frac{d}{c} = \\\\frac{ad}{bc}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        \\\\(\\\\frac{5}{8} \\\\div \\\\frac{3}{4} = \\\\frac{5}{8} \\\\times \\\\frac{4}{3} = \\\\frac{20}{24} = \\\\) <strong>\\\\(\\\\frac{5}{6}\\\\)</strong>
      </div>

      <h2>Decimals</h2>
      <p>Know the key fraction-to-decimal conversions cold:</p>
      <ul>
        <li><strong>1/2</strong> = 0.5</li>
        <li><strong>1/3</strong> = 0.333...</li>
        <li><strong>1/4</strong> = 0.25</li>
        <li><strong>1/5</strong> = 0.2</li>
        <li><strong>1/8</strong> = 0.125</li>
        <li><strong>3/4</strong> = 0.75</li>
        <li><strong>2/3</strong> = 0.667</li>
      </ul>

      <h2>Percentages</h2>
      <p>Percentage questions are almost guaranteed. The key formula:</p>
      <div class="formula-block">\\\\[\\\\text{% Change} = \\\\frac{\\\\text{New} - \\\\text{Old}}{\\\\text{Old}} \\\\times 100\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A value goes from 1200 to 1500. Percent increase:<br>
        = (1500 - 1200) / 1200 × 100 = 300/1200 × 100 = <strong>25%</strong>
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Pro Tip</div>
        To find X% of a number: move the decimal two places left, then multiply.<br>
        15% of 240 = 0.15 × 240 = <strong>36</strong>
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Markup Then Discount Trap</div>
        A $50 item marked up 40% then discounted 25%:<br>
        Step 1: $50 × 1.40 = $70<br>
        Step 2: $70 × 0.75 = <strong>$52.50</strong><br>
        It is NOT the same as a 15% net increase! Percentages on different bases don''t cancel cleanly.
      </div>

      <h2>Ratios</h2>
      <p>Ratios compare quantities. Use <strong>cross-multiplication</strong> to solve ratio problems.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Boys to girls ratio is 3:5. Total students = 40. How many boys?<br>
        Total parts = 3 + 5 = 8<br>
        Boys = (3/8) × 40 = <strong>15</strong>
      </div>', 1)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (2, 'MATH SKILLS', 'Algebra', 'Linear equations, systems, exponents, quadratics, and inequalities', ARRAY['Equations','Exponents','Quadratics'], '<h1>Algebra</h1>
      <p class="lesson-subtitle">Solve equations, manipulate exponents, work with systems, and tackle quadratics confidently.</p>

      <h2>Linear Equations</h2>
      <p>Isolate the variable by performing the same operation on both sides.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">3x - 7 = 14</span><br>
        3x = 21<br>
        x = <strong>7</strong>
      </div>

      <h2>Systems of Equations</h2>
      <p>Two methods: <strong>substitution</strong> and <strong>elimination</strong>. Use whichever is faster for the given problem.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example (Elimination)</div>
        <span class="math-inline">2x + y = 7</span><br>
        <span class="math-inline">x - y = 2</span><br>
        Add both equations: 3x = 9 → x = 3<br>
        Plug back: 3 - y = 2 → y = <strong>1</strong><br>
        Solution: <strong>x = 3, y = 1</strong>
      </div>

      <h2>Exponent Rules</h2>
      <p>Memorize these &mdash; they appear in nearly every test.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Core Rules</div>
        <span class="math-inline">xᵃ · xᵇ = xᵃ⁺ᵇ</span><br>
        <span class="math-inline">xᵃ / xᵇ = xᵃ⁻ᵇ</span><br>
        <span class="math-inline">(xᵃ)ᵇ = xᵃᵇ</span><br>
        <span class="math-inline">x⁰ = 1</span> (any non-zero base)<br>
        <span class="math-inline">x⁻ⁿ = 1/xⁿ</span>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">x³ · x⁵ / x²</span> = x³⁺⁵⁻² = <strong>x⁶</strong>
      </div>

      <h2>Factoring</h2>
      <p>Look for two numbers that multiply to <code>c</code> and add to <code>b</code> in <span class="math-inline">x² + bx + c</span>.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">x² - 5x + 6</span><br>
        Numbers that multiply to 6 and add to -5: <strong>-2 and -3</strong><br>
        = <strong>(x - 2)(x - 3)</strong>
      </div>

      <h2>Quadratic Formula</h2>
      <p>When factoring isn''t obvious, use the quadratic formula.</p>
      <div class="formula-block">\\\\[x = \\\\frac{-b \\\\pm \\\\sqrt{b^{2} - 4ac}}{2a}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">2x² + 5x - 3 = 0</span> → a=2, b=5, c=-3<br>
        Discriminant: 25 - 4(2)(-3) = 25 + 24 = 49<br>
        x = (-5 ± 7) / 4<br>
        x = 2/4 = <strong>1/2</strong> or x = -12/4 = <strong>-3</strong>
      </div>

      <h2>Inequalities</h2>
      <div class="callout callout-warning">
        <div class="callout-title">Critical Rule</div>
        When you multiply or divide both sides by a <strong>negative number</strong>, you must <strong>FLIP the inequality sign</strong>.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <code>-3(2x - 4) > 18</code><br>
        -6x + 12 > 18<br>
        -6x > 6<br>
        x < -1 (flipped because we divided by -6)
      </div>

      <h2>Absolute Value</h2>
      <p><span class="math-inline">|x - a| = b</span> splits into two equations: <span class="math-inline">x - a = b</span> and <span class="math-inline">x - a = -b</span>.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">|x - 4| = 7</span><br>
        x - 4 = 7 → x = <strong>11</strong><br>
        x - 4 = -7 → x = <strong>-3</strong>
      </div>

      <h2>Function Evaluation</h2>
      <p>Replace the variable with the given value and compute.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">f(x) = 2x² - 3x + 1</span>, find f(3)<br>
        = 2(9) - 3(3) + 1 = 18 - 9 + 1 = <strong>10</strong>
      </div>

      <h2>Logarithms &amp; Exponential Equations</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Key Relationship</div>
        <span class="math-inline">log<sub>b</sub>(x) = y</span> means <span class="math-inline">bʸ = x</span>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        <span class="math-inline">log₂(x) = 5</span> → 2⁵ = x → x = <strong>32</strong><br><br>
        <span class="math-inline">2ˣ⁺¹ = 16</span> → 2ˣ⁺¹ = 2⁴ → x+1 = 4 → x = <strong>3</strong>
      </div>', 2)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (3, 'MATH SKILLS', 'Geometry', 'Angles, Pythagorean theorem, special triangles, circles, areas, volumes, coordinate geometry', ARRAY['Triangles','Circles','Coordinate'], '<h1>Geometry</h1>
      <p class="lesson-subtitle">Angles, triangles, circles, areas, volumes, and coordinate geometry &mdash; all the spatial reasoning the OAR demands.</p>

      <h2>Angles</h2>
      <ul>
        <li><strong>Complementary</strong> angles sum to <strong>90°</strong></li>
        <li><strong>Supplementary</strong> angles sum to <strong>180°</strong></li>
        <li>All angles in a <strong>triangle</strong> sum to <strong>180°</strong></li>
      </ul>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Triangle with angles 45° and 70°. Third angle:<br>
        180 - 45 - 70 = <strong>65°</strong><br><br>
        An angle is 35°. Its supplement: 180 - 35 = <strong>145°</strong>
      </div>

      <h2>Pythagorean Theorem</h2>
      <div class="formula-block">\\\\[a^{2} + b^{2} = c^{2}\\\\]</div>
      <p>Where <code>c</code> is always the <strong>hypotenuse</strong> (longest side, opposite the right angle).</p>
      <div class="callout callout-tip">
        <div class="callout-title">Memorize These Triples</div>
        <strong>3-4-5</strong> (and multiples: 6-8-10, 9-12-15)<br>
        <strong>5-12-13</strong><br>
        <strong>8-15-17</strong><br>
        Recognizing these saves massive calculation time.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Legs = 5 and 12. Hypotenuse:<br>
        5² + 12² = 25 + 144 = 169<br>
        √169 = <strong>13</strong>
      </div>

      <h2>Special Right Triangles</h2>
      <div class="callout callout-formula">
        <div class="callout-title">45-45-90 Triangle</div>
        Sides: <span class="math-inline">x, x, x√2</span><br>
        Both legs are equal. Hypotenuse = leg × √2
      </div>
      <div class="callout callout-formula">
        <div class="callout-title">30-60-90 Triangle</div>
        Sides: <span class="math-inline">x, x√3, 2x</span><br>
        Short leg (opposite 30°) = x<br>
        Long leg (opposite 60°) = x√3<br>
        Hypotenuse (opposite 90°) = 2x
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        30-60-90 triangle, short leg = 5.<br>
        Hypotenuse = 2 × 5 = <strong>10</strong>
      </div>

      <h2>Circles</h2>
      <div class="formula-block">\\\\[C = 2\\\\pi r \\\\quad|\\\\quad A = \\\\pi r^{2}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Circle with radius 6:<br>
        Area = π(6)² = <strong>36π</strong><br><br>
        Arc length for a 60° sector, r = 12:<br>
        Arc = (60/360) × 2π(12) = (1/6)(24π) = <strong>4π</strong>
      </div>

      <h2>Area Formulas</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Key Formulas</div>
        Rectangle: <span class="math-inline">A = L × W</span><br>
        Triangle: <span class="math-inline">A = ½ × b × h</span><br>
        Trapezoid: <span class="math-inline">A = ½(b₁ + b₂) × h</span>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Trapezoid with bases 8 and 12, height 5:<br>
        A = ½(8 + 12) × 5 = ½(20)(5) = <strong>50</strong>
      </div>

      <h2>Volume Formulas</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Key Formulas</div>
        Cylinder: <span class="math-inline">V = πr²h</span><br>
        Sphere: <span class="math-inline">V = (4/3)πr³</span><br>
        Cone: <span class="math-inline">V = (1/3)πr²h</span>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Cylinder: r = 3, h = 10<br>
        V = π(3)²(10) = π(9)(10) = <strong>90π</strong>
      </div>

      <h2>Coordinate Geometry</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Key Formulas</div>
        Slope: <span class="math-inline">m = (y₂ - y₁) / (x₂ - x₁)</span><br>
        Distance: <span class="math-inline">d = √((x₂-x₁)² + (y₂-y₁)²)</span><br>
        Midpoint: <span class="math-inline">((x₁+x₂)/2, (y₁+y₂)/2)</span><br>
        Slope-intercept: <span class="math-inline">y = mx + b</span>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Points (2,5) and (6,13):<br>
        Slope = (13-5)/(6-2) = 8/4 = <strong>2</strong><br><br>
        Points (1,3) and (4,7):<br>
        Distance = √((4-1)² + (7-3)²) = √(9+16) = √25 = <strong>5</strong>
      </div>', 3)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (4, 'MATH SKILLS', 'Word Problems', 'Distance-rate-time, work rate, mixtures, probability, averages, and interest', ARRAY['D=RT','Work Rate','Probability'], '<h1>Word Problems</h1>
      <p class="lesson-subtitle">Translate real-world scenarios into equations. This is where the OAR math section separates strong scorers from the rest.</p>

      <h2>Distance = Rate × Time</h2>
      <div class="formula-block">\\\\[D = R \\\\times T\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A car drives 55 mph for 3.5 hours. Distance:<br>
        D = 55 × 3.5 = <strong>192.5 miles</strong>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example: Opposite Directions</div>
        Two trains leave from points 490 miles apart, heading toward each other at 60 mph and 80 mph. When do they meet?<br>
        Combined rate = 60 + 80 = 140 mph<br>
        T = 490 / 140 = <strong>3.5 hours</strong>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example: Wind Speed</div>
        A plane flies 600 miles with a tailwind in 2 hours, and returns against the wind in 3 hours.<br>
        With wind: 600/2 = 300 mph = p + w<br>
        Against wind: 600/3 = 200 mph = p - w<br>
        Add: 2p = 500, p = 250. Wind speed: w = 300 - 250 = <strong>50 mph</strong>
      </div>

      <h2>Work Rate Problems</h2>
      <div class="formula-block">\\\\[\\\\frac{1}{A} + \\\\frac{1}{B} = \\\\frac{1}{T}\\\\]</div>
      <p>Where A and B are hours each person takes alone, and T is time working together.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Worker A finishes in 5 hours, Worker B in 3 hours. Together:<br>
        1/5 + 1/3 = 3/15 + 5/15 = 8/15<br>
        T = 15/8 = <strong>1.875 hours</strong> (1 hr 52.5 min)
      </div>

      <h2>Mixture Problems</h2>
      <p>Use the equation: <strong>amount of substance before = amount of substance after</strong>.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        10L of 20% salt solution. Add water to make 8% solution. How much total?<br>
        Salt stays constant: 10 × 0.20 = 2L of salt<br>
        2 = 0.08 × Total → Total = 2/0.08 = 25L<br>
        Water to add: 25 - 10 = <strong>15L</strong>
      </div>

      <h2>Probability</h2>
      <div class="formula-block">\\\\[P(\\\\text{event}) = \\\\frac{\\\\text{favorable outcomes}}{\\\\text{total outcomes}}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        4 red, 3 blue, 5 green marbles. P(blue):<br>
        = 3 / (4+3+5) = 3/12 = <strong>1/4</strong>
      </div>

      <h2>Averages</h2>
      <div class="formula-block">\\\\[\\\\text{Average} = \\\\frac{\\\\text{Sum}}{\\\\text{Count}}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Scores: 78, 85, 92, 88. Need average of 86 after 5 tests. What 5th score?<br>
        Target sum = 86 × 5 = 430<br>
        Current sum = 78 + 85 + 92 + 88 = 343<br>
        5th score = 430 - 343 = <strong>87</strong>
      </div>

      <h2>Similar Triangles (Shadow Problems)</h2>
      <p>When two triangles are similar, their sides are proportional.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A 6ft man casts a 4ft shadow. A flagpole casts a 20ft shadow. Flagpole height:<br>
        6/4 = h/20 → h = 6 × 20/4 = <strong>30 ft</strong>
      </div>

      <h2>Simple Interest</h2>
      <div class="formula-block">\\\\[I = P \\\\times r \\\\times t \\\\quad|\\\\quad \\\\text{Total} = P + I\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        $5,000 at 6% for 3 years:<br>
        I = 5000 × 0.06 × 3 = $900<br>
        Total = 5000 + 900 = <strong>$5,900</strong>
      </div>

      <h2>Reverse Percentage (Original Price)</h2>
      <div class="callout callout-tip">
        <div class="callout-title">Pro Tip</div>
        If the <em>discounted</em> price is given, divide by (1 - discount rate) to find the original.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Shirt costs $45 after 25% off. Original price:<br>
        $45 = Original × 0.75<br>
        Original = 45 / 0.75 = <strong>$60</strong>
      </div>', 4)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (5, 'READING COMPREHENSION', 'Main Idea & Purpose', 'Identifying topic, main idea, theme, and author''s purpose', ARRAY['Main Idea','Purpose','Strategy'], '<h1>Main Idea &amp; Purpose</h1>
      <p class="lesson-subtitle">The reading section tests whether you can quickly extract what a passage is really saying and why the author wrote it.</p>

      <h2>Topic vs. Main Idea vs. Theme</h2>
      <ul>
        <li><strong>Topic</strong>: What the passage is about in 1-3 words (e.g., "coral reef decline")</li>
        <li><strong>Main Idea</strong>: The author''s primary point about the topic (a full sentence)</li>
        <li><strong>Theme</strong>: The underlying message or lesson (usually for literary passages)</li>
      </ul>
      <div class="callout callout-tip">
        <div class="callout-title">Strategy</div>
        Read the <strong>first and last sentence</strong> of each paragraph carefully. The main idea is almost always stated or strongly implied there.
      </div>

      <h2>Author''s Purpose</h2>
      <p>Every passage exists to do one of three things:</p>
      <ol>
        <li><strong>Inform</strong> &mdash; presents facts, data, explanations objectively</li>
        <li><strong>Persuade</strong> &mdash; argues a position, urges action</li>
        <li><strong>Entertain</strong> &mdash; uses narrative, humor, vivid description</li>
      </ol>
      <div class="callout callout-formula">
        <div class="callout-title">Clue Words</div>
        <strong>Persuade:</strong> "should," "must," "it is essential," "clearly"<br>
        <strong>Inform:</strong> statistics, dates, neutral language, technical terms<br>
        <strong>Entertain:</strong> dialogue, imagery, anecdotes
      </div>

      <h2>Reading Strategy for OAR Passages</h2>
      <ol>
        <li><strong>Skim first</strong> (30 seconds) &mdash; read first/last sentences of each paragraph</li>
        <li><strong>Read the question</strong> &mdash; know what you''re looking for</li>
        <li><strong>Re-read targeted sections</strong> &mdash; don''t re-read the whole passage</li>
        <li><strong>Eliminate wrong answers</strong> &mdash; often easier than picking the right one</li>
      </ol>

      <div class="callout callout-warning">
        <div class="callout-title">Common Trap</div>
        Answer choices that are <strong>true but too narrow</strong> are wrong. The main idea must cover the <em>whole</em> passage, not just one paragraph.
      </div>

      <h2>Practice Recognizing Purpose</h2>
      <div class="callout callout-example">
        <div class="callout-title">Example Passage Snippet</div>
        "Sleep deprivation among shift workers has reached alarming levels, with studies showing that 17 hours without sleep produces impairment equivalent to a blood alcohol concentration of 0.05%..."<br><br>
        <strong>Purpose:</strong> Inform (with a concerned tone, but primarily presenting data).<br>
        <strong>Tone:</strong> Concerned and somewhat critical.
      </div>', 5)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (6, 'READING COMPREHENSION', 'Inference & Detail', 'Drawing conclusions, finding details, vocabulary in context, elimination strategy', ARRAY['Inference','Detail','Vocab'], '<h1>Inference &amp; Detail</h1>
      <p class="lesson-subtitle">Answer questions about what the passage states explicitly and what it implies &mdash; but never go beyond the text.</p>

      <h2>Detail Questions</h2>
      <p>These ask "According to the passage..." or "The author states that..." The answer is <strong>directly in the text</strong>.</p>
      <div class="callout callout-tip">
        <div class="callout-title">Keyword Scanning</div>
        Find a unique word from the question, scan the passage for that word, read the surrounding sentence(s). The answer is right there.
      </div>

      <h2>Inference Questions</h2>
      <p>These ask "It can be inferred..." or "The passage suggests..." The answer is <strong>strongly implied</strong> but not explicitly stated.</p>
      <div class="callout callout-warning">
        <div class="callout-title">Critical Rule</div>
        <strong>NEVER</strong> use outside knowledge. Every correct inference must be supported by evidence <em>in the passage</em>. If you have to make a logical leap beyond the text, the answer is wrong.
      </div>

      <h2>Vocabulary in Context</h2>
      <p>Don''t use the word''s most common meaning. Use the meaning that fits <strong>this specific sentence</strong>.</p>
      <div class="callout callout-tip">
        <div class="callout-title">Strategy</div>
        Replace the word with each answer choice. Read the sentence with the replacement. The one that maintains the original meaning is correct.
      </div>

      <h2>Elimination Strategy</h2>
      <p>On the OAR, wrong answers fall into predictable categories. Learn to spot them instantly:</p>
      <div class="callout callout-formula">
        <div class="callout-title">Four Types of Wrong Answers</div>
        <strong>1. Too Extreme</strong> &mdash; uses words like "always," "never," "all," "none" when the passage is more nuanced<br>
        <strong>2. True But Not Stated</strong> &mdash; correct in the real world but not supported by this passage<br>
        <strong>3. Opposite</strong> &mdash; contradicts what the passage says (these trap speed readers)<br>
        <strong>4. Too Narrow</strong> &mdash; covers only one detail when the question asks for the main point
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example Application</div>
        A passage discusses both benefits and challenges of electric vehicles. Question: What is the author''s position?<br><br>
        (A) EVs are the only solution to climate change ← <strong>Too extreme</strong><br>
        (B) Battery technology is improving rapidly ← <strong>Too narrow</strong><br>
        (C) The environmental benefit is real but more nuanced than commonly believed ← <strong>Correct</strong><br>
        (D) Gasoline cars are better than EVs ← <strong>Opposite</strong>
      </div>

      <h2>Reading Speed Tips</h2>
      <ul>
        <li>Don''t sub-vocalize (say words in your head)</li>
        <li>Read in <strong>chunks</strong> of 3-4 words, not word by word</li>
        <li>Skip filler words &mdash; focus on nouns, verbs, and adjectives</li>
        <li>Don''t re-read unless you truly lost the thread</li>
        <li>You have roughly <strong>1.5 minutes per question</strong> including reading time</li>
      </ul>', 6)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (18, 'READING COMPREHENSION', 'Common Text Organizations', 'Chronological, cause-effect, problem-solution, compare-contrast, and sequence patterns', ARRAY['Text Structure','Cause Effect','Compare Contrast','Sequence'], '<h1>Common Text Organizations</h1>
      <p class="lesson-subtitle">Recognizing how a passage is structured lets you predict where answers hide. Every OAR reading passage follows one of these patterns.</p>

      <h2>Chronological Order</h2>
      <p>Events are presented in the <strong>order they occurred in time</strong>. This is the most straightforward structure and appears frequently in biographies, historical accounts, and process descriptions.</p>
      <div class="callout callout-tip">
        <div class="callout-title">Strategy</div>
        When you spot dates, time references, or words like "before," "after," "during," and "eventually," you are reading chronological order. Map events on a mental timeline to answer sequence questions quickly.
      </div>

      <h2>Cause and Effect</h2>
      <p>The author explains <strong>why something happened</strong> (cause) and <strong>what resulted</strong> (effect). Watch for three common patterns:</p>
      <ul>
        <li><strong>Single cause → multiple effects:</strong> one event triggers several outcomes</li>
        <li><strong>Multiple causes → single effect:</strong> several factors combine to produce one result</li>
        <li><strong>Cause-effect chains:</strong> A causes B, which causes C, and so on</li>
      </ul>
      <div class="callout callout-formula">
        <div class="callout-title">Signal Words</div>
        <strong>Cause:</strong> "because," "since," "due to," "as a result of," "stems from"<br>
        <strong>Effect:</strong> "consequently," "therefore," "thus," "as a result," "led to," "so"
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Watch Out</div>
        Persuasive essays often use cause-and-effect reasoning, but readers should question whether the relationship is truly conclusive or merely correlation presented as causation.
      </div>

      <h2>Problem-Solution</h2>
      <p>The author presents a <strong>problem first</strong>, then proposes one or more <strong>solutions</strong>. Questions often ask you to identify the problem, the solution, or evaluate whether the solution actually addresses the problem.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        "Urban traffic congestion costs commuters an average of 54 hours per year. To address this, cities have expanded public transit, implemented congestion pricing, and promoted remote work."<br><br>
        <strong>Problem:</strong> Traffic congestion and lost time<br>
        <strong>Solutions:</strong> Public transit, congestion pricing, remote work<br>
        Watch for <strong>author bias</strong> &mdash; the author may favor one solution over others through word choice and emphasis.
      </div>

      <h2>Compare and Contrast</h2>
      <p><strong>Comparison</strong> highlights similarities; <strong>contrast</strong> highlights differences. A fair analysis presents both sides equally, but authors sometimes weight one side to persuade.</p>
      <ul>
        <li><strong>Comparison signals:</strong> "similarly," "likewise," "in the same way," "both," "also"</li>
        <li><strong>Contrast signals:</strong> "however," "on the other hand," "whereas," "unlike," "but," "although"</li>
      </ul>
      <div class="callout callout-tip">
        <div class="callout-title">Strategy</div>
        Draw a quick mental T-chart: left side = Subject A, right side = Subject B. Fill in shared traits (top) and differences (bottom). This makes comparison questions trivial.
      </div>

      <h2>Sequence</h2>
      <p>Similar to chronological order but focused on <strong>steps in a process</strong> rather than historical events. Recipes, instructions, and procedures all use sequence structure.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Signal Words</div>
        "first," "second," "then," "next," "after that," "finally," "last"<br>
        <strong>Note:</strong> Sometimes the sequence is <strong>implied, not stated</strong> &mdash; you must infer the order from context clues.
      </div>', 18)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (19, 'READING COMPREHENSION', 'Reading Informational Texts', 'Literal vs figurative language, inference, author purpose, evaluating arguments, and text features', ARRAY['Informational','Inference','Text Features','Author Purpose'], '<h1>Reading Informational Texts</h1>
      <p class="lesson-subtitle">Informational texts make up the majority of OAR reading passages. Master these skills to extract meaning quickly and accurately.</p>

      <h2>Literal vs. Figurative Language</h2>
      <p><strong>Literal language</strong> means exactly what it says. <strong>Figurative language</strong> uses words in non-literal ways to create vivid meaning:</p>
      <ul>
        <li><strong>Simile:</strong> comparison using "like" or "as" &mdash; "The engine roared like thunder"</li>
        <li><strong>Metaphor:</strong> direct comparison without "like/as" &mdash; "The economy is a house of cards"</li>
        <li><strong>Imagery:</strong> language that appeals to the senses &mdash; "The acrid smell of burning rubber filled the hangar"</li>
      </ul>
      <div class="callout callout-tip">
        <div class="callout-title">OAR Tip</div>
        Most OAR passages use literal language because they are informational. When you encounter figurative language, the question will usually ask what the author <strong>means</strong> by it &mdash; translate it into a literal statement to find the correct answer.
      </div>

      <h2>Explicit vs. Implicit Information</h2>
      <p><strong>Explicit information</strong> is stated directly in the text &mdash; you can point to the exact sentence. <strong>Implicit information</strong> is not stated but must be <strong>inferred</strong> from context, tone, or details.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Text: "After the third recall in two years, the company''s stock price dropped 40%."<br><br>
        <strong>Explicit:</strong> Three recalls occurred; stock dropped 40%.<br>
        <strong>Implicit:</strong> The company has quality control problems; investors lost confidence.
      </div>

      <h2>Making Inferences from Informational Text</h2>
      <p>An inference combines <strong>text evidence</strong> with your <strong>prior knowledge</strong> to reach a conclusion the author implies but does not state outright.</p>
      <p>Different text types require different kinds of inferences:</p>
      <ul>
        <li><strong>Autobiography/biography:</strong> infer motivations behind events and decisions</li>
        <li><strong>Expository text:</strong> infer problems, solutions, or unstated connections</li>
        <li><strong>Persuasive text:</strong> infer the supporting ideas and assumptions behind the argument</li>
      </ul>
      <div class="callout callout-warning">
        <div class="callout-title">Common Mistake</div>
        An inference must be <strong>supported by the text</strong>. If you cannot point to specific evidence, your inference is speculation &mdash; and the OAR will have a more grounded answer choice.
      </div>

      <h2>Determining Author''s Purpose</h2>
      <p>Go beyond "inform, persuade, entertain" and consider the author''s deeper <strong>motivations</strong>:</p>
      <ul>
        <li><strong>Stated purpose:</strong> explicitly declared ("This report examines...")</li>
        <li><strong>Unstated purpose:</strong> revealed through tone, emphasis, and word choice</li>
        <li><strong>Hidden agendas:</strong> when the stated purpose <strong>contradicts</strong> the content &mdash; for example, a "balanced review" that only presents one side</li>
      </ul>

      <h2>Evaluating Arguments</h2>
      <p>To evaluate an argument, first identify the <strong>conclusion</strong> (what the author wants you to believe), then examine the <strong>premises</strong> (reasons given to support it).</p>
      <ul>
        <li><strong>Deductive reasoning:</strong> general principle → specific conclusion (if premises are true, conclusion must be true)</li>
        <li><strong>Inductive reasoning:</strong> specific evidence → general conclusion (conclusion is probable but not guaranteed)</li>
      </ul>
      <div class="callout callout-tip">
        <div class="callout-title">Strategy</div>
        Ask yourself: "Do the premises actually support the conclusion?" If the evidence is weak, anecdotal, or irrelevant, the argument is flawed &mdash; and the OAR may test you on recognizing that.
      </div>

      <h2>Text Features</h2>
      <p>Informational texts use structural features to organize content. Knowing these helps you navigate passages faster:</p>
      <div class="callout callout-formula">
        <div class="callout-title">Key Text Features</div>
        <strong>Navigation:</strong> title, table of contents, index, appendix, glossary<br>
        <strong>Emphasis:</strong> boldface, headings, subheadings, footnotes, bullet points, sidebar<br>
        <strong>Visual:</strong> illustrations, captions, charts, diagrams, graphs, maps, timelines
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        If a question asks "Where would you find the definition of a technical term?" the answer is the <strong>glossary</strong>. If it asks where to find a specific topic quickly, the answer is the <strong>index</strong>. Headings and subheadings help you locate relevant sections without re-reading the entire passage.
      </div>', 19)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (20, 'READING COMPREHENSION', 'Technical Language', 'Technical vs literary language, writing for different audiences, and credibility', ARRAY['Technical Language','Passive Voice','Non-Technical','Audience'], '<h1>Technical Language</h1>
      <p class="lesson-subtitle">Understanding how technical language works &mdash; and how to adapt it &mdash; is essential for OAR reading passages that deal with specialized topics.</p>

      <h2>Technical vs. Literary Language</h2>
      <p><strong>Technical language</strong> is impersonal, concise, and professional. It prioritizes clarity and precision over style. Key characteristics:</p>
      <ul>
        <li><strong>Passive voice:</strong> "This was found to be effective" instead of "We found this effective"</li>
        <li><strong>Precise terminology:</strong> specific, standardized vocabulary</li>
        <li><strong>Objective tone:</strong> avoids emotional language and personal opinion</li>
        <li><strong>Concise structure:</strong> says what needs to be said with no extra words</li>
      </ul>
      <p><strong>Literary language</strong>, by contrast, uses active voice, vivid descriptions, figurative language, and personal perspective to engage the reader emotionally.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example Comparison</div>
        <strong>Technical:</strong> "The specimen was subjected to thermal stress at 450°C for 120 minutes. Structural deformation was observed at the 90-minute mark."<br><br>
        <strong>Literary:</strong> "We pushed the metal to its breaking point, blasting it with heat until it finally buckled under the strain."<br><br>
        Both describe the same event. The technical version is precise and measurable; the literary version is vivid and engaging.
      </div>

      <h2>Writing for Non-Technical Audiences</h2>
      <p>When communicating technical content to a general audience, the goal shifts from <strong>maximum detail</strong> to <strong>maximum understanding</strong>:</p>
      <ul>
        <li>Prioritize the <strong>message</strong> over technical completeness</li>
        <li>Use <strong>everyday language</strong> wherever possible</li>
        <li>When technical terms are unavoidable, <strong>define them immediately</strong></li>
        <li>Use analogies and examples to bridge the knowledge gap</li>
      </ul>
      <div class="callout callout-tip">
        <div class="callout-title">OAR Tip</div>
        If a passage shifts from technical to plain language, the question may ask <strong>why</strong> the author made that shift. The answer is almost always "to make the content accessible to a broader audience."
      </div>

      <h2>Adapting Language for Different Audiences</h2>
      <p>The same information must be communicated differently depending on who is reading it:</p>
      <ul>
        <li><strong>Government/corporate:</strong> formal tone, precise language, structured format</li>
        <li><strong>General citizens:</strong> plain language, real-world examples, relatable context</li>
        <li><strong>NGOs/nonprofits:</strong> mission-driven framing, impact-focused language</li>
        <li><strong>Schools/educational:</strong> simplified vocabulary, step-by-step explanations</li>
      </ul>
      <div class="callout callout-warning">
        <div class="callout-title">Key Principle</div>
        The best communicators use <strong>non-technical terms and normal everyday language</strong> regardless of their expertise level. Complexity in language does not equal quality &mdash; clarity does.
      </div>

      <h2>Credibility Through Technical Language</h2>
      <p>When used appropriately, technical vocabulary <strong>demonstrates understanding</strong> and <strong>suggests credibility</strong>. An author who uses correct terminology signals expertise in the subject matter.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Consider two statements:<br><br>
        (A) "The plane went up fast and then leveled off."<br>
        (B) "The aircraft achieved a positive rate of climb at V2 speed and transitioned to cruise altitude."<br><br>
        Statement B uses precise aviation terminology, which signals the author has domain knowledge. On the OAR, recognizing this difference helps you evaluate author credibility and expertise.
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Strategy</div>
        When the OAR asks about the effect of technical language in a passage, the answer usually involves <strong>establishing credibility</strong>, <strong>demonstrating expertise</strong>, or <strong>ensuring precision</strong> &mdash; not intimidating the reader.
      </div>', 20)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (7, 'MECHANICAL COMPREHENSION', 'Forces & Newton''s Laws', 'Three laws of motion, weight, friction, free fall', ARRAY['F=ma','Friction','Free Fall'], '<h1>Forces &amp; Newton''s Laws</h1>
      <p class="lesson-subtitle">OK, Newton''s Laws. These three laws are the foundation of EVERYTHING in mechanical comprehension. And here''s the beautiful thing &mdash; once you truly understand them, about half the mechanical questions on the OAR become obvious. Let me break each one down in a way that actually sticks.</p>

      <!-- ===== FIRST LAW ===== -->
      <h2>Newton''s First Law &mdash; Inertia</h2>
      <p>Here''s the idea in plain English: <strong>an object at rest stays at rest, and an object in motion stays in motion &mdash; UNLESS something pushes or pulls it.</strong> That''s it. Objects are lazy. They don''t change what they''re doing unless a force makes them.</p>

      <div class="callout callout-tip">
        <div class="callout-title">Think About It This Way</div>
        Why do you lurch forward when a car slams the brakes? Your body was moving and wanted to <strong>keep moving</strong>. The car stopped, but you didn''t &mdash; at least not until the seatbelt caught you. That''s inertia in action. It''s also why your coffee spills when you brake suddenly &mdash; the coffee was moving forward and it doesn''t "know" the cup stopped.
      </div>

      <p>Inertia is just a fancy word for <em>resistance to change</em>. The more mass something has, the more inertia it has. A bowling ball is harder to get rolling than a tennis ball &mdash; and once it IS rolling, it''s harder to stop. Same concept.</p>

      <div class="callout callout-example">
        <div class="callout-title">OAR-Style Question</div>
        "A ball is sitting on a table in a vacuum. No forces act on it. What happens?"<br><br>
        The answer is always: <strong>nothing</strong>. It just sits there. Forever. An object at rest stays at rest unless something pushes it. Don''t overthink these &mdash; the first law makes them free points.
      </div>

      <div class="callout callout-tip">
        <div class="callout-title">More Real-World Examples</div>
        <ul>
          <li><strong>Seatbelts</strong> &mdash; exist because of inertia. In a crash, the car stops but your body keeps going.</li>
          <li><strong>Astronauts floating</strong> &mdash; in space there''s no friction or air resistance, so once you push off a wall, you drift forever until something stops you. Pure first law.</li>
          <li><strong>Tablecloth trick</strong> &mdash; yank a tablecloth fast enough and the dishes stay put. Their inertia resists the quick horizontal pull.</li>
        </ul>
      </div>

      <p>One more critical insight: if an object is moving at <strong>constant velocity</strong> (not speeding up, not slowing down, not changing direction), then the net force on it is <strong>zero</strong>. All the forces are balanced. The OAR loves testing this &mdash; constant velocity means zero net force, every time.</p>

      <!-- ===== SECOND LAW ===== -->
      <h2>Newton''s Second Law &mdash; F = ma</h2>
      <p>This is THE formula of physics. If you remember one equation from this entire course, make it this one:</p>

      <div class="formula-block">\\\\[F = m \\\\times a\\\\]</div>

      <p>Force equals mass times acceleration. Let me unpack what that actually means: if you push something, it accelerates. Push it harder (more force), it accelerates faster. But if the thing is heavier (more mass), it accelerates slower for the same push. That''s the whole law.</p>

      <div class="callout callout-example">
        <div class="callout-title">Let''s Walk Through One</div>
        A 5 kg box sits on a frictionless floor. You push it with 20 N of force. How fast does it accelerate?<br><br>
        Rearrange: \\\\(a = \\\\frac{F}{m} = \\\\frac{20}{5} = 4 \\\\text{ m/s}^2\\\\)<br><br>
        OK, but what does <strong>4 m/s²</strong> actually MEAN? It means every second, the box speeds up by 4 meters per second. After 1 second it''s going 4 m/s. After 2 seconds, 8 m/s. After 3 seconds, 12 m/s. It keeps getting faster as long as you keep pushing.
      </div>

      <div class="callout callout-formula">
        <div class="callout-title">The Three Rearrangements You Need</div>
        <strong>Find Force:</strong> \\\\(F = m \\\\times a\\\\)<br>
        <strong>Find Mass:</strong> \\\\(m = \\\\frac{F}{a}\\\\)<br>
        <strong>Find Acceleration:</strong> \\\\(a = \\\\frac{F}{m}\\\\)<br><br>
        It''s all the same equation, just solved for different things. The OAR will give you two values and ask for the third. Every time.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Bigger Example</div>
        A 1000 kg car accelerates from 0 to 20 m/s in 10 seconds. What''s the net force?<br><br>
        Step 1: Find acceleration. \\\\(a = \\\\frac{\\\\Delta v}{t} = \\\\frac{20 - 0}{10} = 2 \\\\text{ m/s}^2\\\\)<br>
        Step 2: Find force. \\\\(F = m \\\\times a = 1000 \\\\times 2 = \\\\textbf{2000 N}\\\\)<br><br>
        That''s about 450 pounds of force. You can feel that push in your seat when a car accelerates &mdash; that''s 2000 N pushing you forward.
      </div>

      <h3>Weight = F = ma (Where a = Gravity)</h3>
      <p>Here''s something that trips people up: your <strong>weight</strong> is just a force. Specifically, it''s F = ma where "a" is gravity (9.8 m/s², or 10 on the OAR for easy math).</p>

      <div class="formula-block">\\\\[W = m \\\\times g \\\\quad (g = 9.8 \\\\text{ m/s}^2, \\\\text{ or } 10 \\\\text{ on the OAR})\\\\]</div>

      <div class="callout callout-example">
        <div class="callout-title">Quick Weight Calculation</div>
        A 100 kg person: \\\\(W = 100 \\\\times 9.8 = 980 \\\\text{ N}\\\\)<br>
        (Or with OAR rounding: \\\\(100 \\\\times 10 = 1000 \\\\text{ N}\\\\))<br><br>
        <strong>Mass</strong> is how much stuff is in you &mdash; it never changes. <strong>Weight</strong> is how hard gravity pulls on that stuff &mdash; it changes depending on where you are. You''d weigh less on the Moon (weaker gravity) but your mass stays the same.
      </div>

      <!-- ===== THIRD LAW ===== -->
      <h2>Newton''s Third Law &mdash; Action/Reaction</h2>
      <p>For every action, there is an <strong>equal and opposite reaction</strong>. Sounds simple, right? But here''s what MOST people get wrong about this law: <strong>the two forces act on DIFFERENT objects</strong>.</p>

      <div class="callout callout-warning">
        <div class="callout-title">The #1 Mistake on the OAR</div>
        Students see "equal and opposite" and think the forces cancel out. They don''t! They CAN''T cancel out because they act on different objects. If I push a wall with 15 N, the wall pushes ME back with 15 N. One force is on the wall, the other is on me &mdash; two different objects, two different forces.<br><br>
        <strong>If the OAR asks "do action-reaction forces cancel?" the answer is ALWAYS no.</strong>
      </div>

      <div class="callout callout-example">
        <div class="callout-title">The Wall Push</div>
        You push a wall with 15 N. What happens?<br><br>
        &bull; Force 1: Your hand pushes the wall → 15 N (on the wall)<br>
        &bull; Force 2: The wall pushes your hand → 15 N backward (on you)<br><br>
        The wall doesn''t move because it''s anchored to the ground. But YOU might slide backward on a slippery floor &mdash; because the wall is pushing you!
      </div>

      <div class="callout callout-tip">
        <div class="callout-title">Think About It This Way &mdash; Rockets</div>
        How does a rocket work in space where there''s nothing to push against? Third law! The rocket''s engines blast exhaust gas backward (action). The gas pushes the rocket forward (reaction). The rocket pushes on the gas, and the gas pushes on the rocket &mdash; equal forces, opposite directions, different objects. That''s how you move in a vacuum.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">More Pairs to Recognize</div>
        <ul>
          <li><strong>Walking:</strong> Your foot pushes the ground backward, the ground pushes your foot forward.</li>
          <li><strong>Swimming:</strong> Your hands push water backward, the water pushes you forward.</li>
          <li><strong>Jumping:</strong> You push the Earth down, the Earth pushes you up.</li>
        </ul>
        In every case, the forces are equal in size, opposite in direction, and on <strong>different objects</strong>.
      </div>

      <!-- ===== FRICTION ===== -->
      <h2>Friction</h2>
      <p>Friction is the force that opposes motion between two surfaces in contact. You need to know one formula and one critical fact:</p>

      <div class="formula-block">\\\\[F_{\\\\text{friction}} = \\\\mu \\\\times N\\\\]</div>

      <p>Where \\\\(\\\\mu\\\\) (mu) is the coefficient of friction (how "grippy" the surfaces are) and N is the normal force (on a flat surface, this equals the object''s weight).</p>

      <div class="callout callout-warning">
        <div class="callout-title">Critical Fact</div>
        <strong>Static friction is GREATER than kinetic friction.</strong> It takes more force to START an object moving than to KEEP it moving. Think about pushing a heavy dresser &mdash; that first push to get it unstuck is the hardest part. Once it''s sliding, it gets easier. The OAR tests this concept frequently.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Net Force with Friction</div>
        You push a box to the right with 50 N. Friction pushes back to the left with 20 N. What''s the net force?<br><br>
        \\\\(F_{\\\\text{net}} = 50 - 20 = \\\\textbf{30 N to the right}\\\\)<br><br>
        The box accelerates to the right. If you want the acceleration, just plug into F = ma: if the box is 10 kg, then \\\\(a = 30/10 = 3 \\\\text{ m/s}^2\\\\).
      </div>

      <!-- ===== FREE FALL ===== -->
      <h2>Free Fall</h2>
      <p>Here''s a fact that''s counterintuitive but absolutely critical: <strong>ALL objects fall at the same rate</strong> (in a vacuum, ignoring air resistance). A bowling ball and a feather dropped from the same height hit the ground at the exact same time. This is because acceleration due to gravity doesn''t depend on mass &mdash; everything accelerates at g = 9.8 m/s².</p>

      <div class="callout callout-formula">
        <div class="callout-title">Free Fall Formulas</div>
        <strong>Velocity after falling for time t:</strong> \\\\(v = g \\\\times t\\\\)<br>
        <strong>Distance fallen:</strong> \\\\(d = \\\\frac{1}{2} \\\\times g \\\\times t^2\\\\)
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Let''s Walk Through It</div>
        An object is dropped from a tall building. After 3 seconds of free fall (using g = 9.8 m/s²):<br><br>
        <strong>How fast is it going?</strong><br>
        \\\\(v = 9.8 \\\\times 3 = 29.4 \\\\text{ m/s}\\\\)<br>
        That''s about 66 mph! After just 3 seconds!<br><br>
        <strong>How far has it fallen?</strong><br>
        \\\\(d = \\\\frac{1}{2} \\\\times 9.8 \\\\times 3^2 = \\\\frac{1}{2} \\\\times 9.8 \\\\times 9 = 44.1 \\\\text{ m}\\\\)<br>
        That''s about 145 feet &mdash; roughly a 14-story building.
      </div>

      <div class="callout callout-tip">
        <div class="callout-title">OAR Tip</div>
        The OAR often uses g = 10 m/s² to keep the math clean. If the numbers come out ugly, try using 10 instead of 9.8 &mdash; that''s probably what they intended.
      </div>

      <!-- ===== PRACTICE ===== -->
      <h2>Try It Yourself</h2>
      <div class="callout callout-example">
        <div class="callout-title">Practice Problems</div>
        <strong>1.</strong> A 3 kg ball is kicked with a force of 24 N. What is its acceleration?<br>
        <em>Hint: a = F/m</em><br><br>
        <strong>2.</strong> You''re standing on a scale in an elevator. The scale reads your normal weight. The elevator starts accelerating upward. Does the scale reading increase, decrease, or stay the same?<br>
        <em>Hint: Think about what "acceleration upward" does to the normal force.</em><br><br>
        <strong>3.</strong> A 50 kg skydiver is in free fall for 4 seconds. How fast are they going? (Use g = 10)<br>
        <em>Hint: v = g × t</em><br><br>
        <strong>4.</strong> Two objects &mdash; a 1 kg ball and a 100 kg anvil &mdash; are dropped from the same height in a vacuum. Which hits the ground first?<br>
        <em>Hint: Re-read the free fall section!</em>
      </div>

      <div class="callout callout-tip">
        <div class="callout-title">Answers</div>
        1. \\\\(a = 24/3 = 8 \\\\text{ m/s}^2\\\\)<br>
        2. <strong>Increases</strong> &mdash; accelerating upward adds to the normal force. You feel heavier.<br>
        3. \\\\(v = 10 \\\\times 4 = 40 \\\\text{ m/s}\\\\) (about 90 mph!)<br>
        4. <strong>They hit at the same time.</strong> In a vacuum, all objects fall at the same rate regardless of mass.
      </div>', 7)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (8, 'MECHANICAL COMPREHENSION', 'Levers & Torque', 'Three classes of levers, the lever formula, mechanical advantage, torque', ARRAY['Levers','Torque','MA'], '<h1>Levers &amp; Torque</h1>
      <p class="lesson-subtitle">Levers are the most tested simple machine on the OAR &mdash; and for good reason. They show up everywhere in real life, and the math behind them is beautifully simple once you see the pattern. Let''s make sure you never miss a lever question again.</p>

      <!-- ===== FLE SYSTEM ===== -->
      <h2>The FLE System &mdash; Three Classes of Levers</h2>
      <p>There are three classes of levers, and I''m going to make sure you NEVER forget which is which. The secret is three letters: <strong>F-L-E</strong>. The letters tell you what''s in the <strong>MIDDLE</strong>:</p>

      <div class="callout callout-formula">
        <div class="callout-title">The FLE Memory System</div>
        <strong>1st Class = F</strong>ulcrum in the middle<br>
        <strong>2nd Class = L</strong>oad in the middle<br>
        <strong>3rd Class = E</strong>ffort in the middle
      </div>

      <p>OK, but what does that actually look like? Let me give you one object for each class that you''ll never forget:</p>

      <div class="callout callout-tip">
        <div class="callout-title">Think About It This Way</div>
        <ul>
          <li><strong>1st Class &mdash; SEESAW.</strong> Picture a playground seesaw. The pivot point (fulcrum) is right in the middle. One kid pushes down on one side (effort), and the other kid goes up on the other side (load). Fulcrum in the middle = 1st class. Scissors work the same way &mdash; the pivot is between your hand and what you''re cutting.</li>
          <li><strong>2nd Class &mdash; WHEELBARROW.</strong> Picture a wheelbarrow full of dirt. The wheel is the fulcrum (at one end). The heavy dirt is the load (in the middle). You lift from the handles (effort at the other end). Load in the middle = 2nd class. A nutcracker works this way too &mdash; the nut sits between the hinge and your hand.</li>
          <li><strong>3rd Class &mdash; FISHING ROD.</strong> You hold the butt of the rod with one hand (that''s the fulcrum). Your other hand pulls up in the middle of the rod (effort in the middle). The fish is at the far end (load). Effort in the middle = 3rd class. Your forearm works like this too &mdash; your elbow is the fulcrum, your bicep pulls in the middle, and whatever you''re holding is the load.</li>
        </ul>
      </div>

      <div class="callout callout-warning">
        <div class="callout-title">The Trick That Makes This Stick Forever</div>
        Picture these three objects in order: <strong>seesaw, wheelbarrow, fishing rod</strong>. That''s 1st, 2nd, 3rd. Three objects, three classes, done. On test day, just think "seesaw &mdash; wheelbarrow &mdash; fishing rod" and you''ll instantly know which class any lever belongs to.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">OAR-Style Question</div>
        "A crowbar is used to pry open a crate. The edge of the crate acts as the fulcrum, which is between where you push and the lid being lifted. What class of lever is this?"<br><br>
        Fulcrum is in the middle → <strong>1st class</strong>. Just like a seesaw.
      </div>

      <!-- ===== BALANCE FORMULA ===== -->
      <h2>The Balance Formula</h2>
      <p>This is the most important equation for lever problems, and it''s beautifully intuitive:</p>

      <div class="formula-block">\\\\[F_1 \\\\times D_1 = F_2 \\\\times D_2\\\\]</div>

      <p>Think of it like a seesaw. A heavier kid has to sit <strong>closer</strong> to the middle to balance a lighter kid who sits farther away. Force times distance on one side must equal force times distance on the other side. That''s it.</p>

      <div class="callout callout-example">
        <div class="callout-title">Let''s Walk Through One Together</div>
        A 40 kg kid sits 3 meters from the fulcrum on one side of a seesaw. Where does a 60 kg kid need to sit on the other side to balance?<br><br>
        Set up the equation: \\\\(40 \\\\times 3 = 60 \\\\times d\\\\)<br>
        Simplify the left side: \\\\(120 = 60 \\\\times d\\\\)<br>
        Solve for d: \\\\(d = \\\\frac{120}{60} = \\\\textbf{2 meters}\\\\)<br><br>
        Makes sense, right? The heavier kid (60 kg) sits closer (2 m) than the lighter kid (40 kg, at 3 m). That''s how seesaws work in real life.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Another One &mdash; With a Crowbar</div>
        You''re using a lever to lift a 300 lb rock. Your effort arm is 6 ft and the load arm is 2 ft. How much force do you need?<br><br>
        \\\\(F \\\\times 6 = 300 \\\\times 2\\\\)<br>
        \\\\(F \\\\times 6 = 600\\\\)<br>
        \\\\(F = \\\\frac{600}{6} = \\\\textbf{100 lbs}\\\\)<br><br>
        You only need 100 lbs of force to lift a 300 lb rock! That''s the magic of levers.
      </div>

      <div class="callout callout-tip">
        <div class="callout-title">OAR Pattern</div>
        The OAR gives you three of the four numbers (F1, D1, F2, D2) and asks for the fourth. It''s always just cross-multiplication. Set up the equation, plug in what you know, and solve for what you don''t. No tricks &mdash; just arithmetic.
      </div>

      <!-- ===== MECHANICAL ADVANTAGE ===== -->
      <h2>Mechanical Advantage</h2>
      <p>Mechanical advantage (MA) tells you how much a lever multiplies your force. The formula is simple:</p>

      <div class="formula-block">\\\\[MA = \\\\frac{\\\\text{Effort Arm}}{\\\\text{Load Arm}}\\\\]</div>

      <div class="callout callout-example">
        <div class="callout-title">What MA Actually Means</div>
        Effort arm = 8 ft, load arm = 2 ft:<br>
        \\\\(MA = \\\\frac{8}{2} = \\\\textbf{4}\\\\)<br><br>
        An MA of 4 means you only need <strong>1/4 the force</strong> to lift the load. If the load weighs 200 lbs, you only need to push with 50 lbs. Pretty powerful, right?
      </div>

      <div class="callout callout-warning">
        <div class="callout-title">The Golden Rule &mdash; You Never Get Something for Nothing</div>
        Here''s the catch that the OAR loves to test: if your effort arm is 4 times longer than the load arm, you need only 1/4 the force &mdash; but you have to push <strong>4 times farther</strong>. You''re trading distance for force.<br><br>
        <strong>Force × Distance = constant.</strong> Less force always means more distance. Always. This is true for levers, pulleys, ramps &mdash; every simple machine. There are no free lunches in physics.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Real-World Connection</div>
        Think about a car jack. You pump the handle up and down many times (lots of distance) to lift a car just a few inches (small distance). But you''re doing it with one hand &mdash; because the mechanical advantage is huge. You''re trading many small pushes for one big lift.
      </div>

      <!-- ===== TORQUE ===== -->
      <h2>Torque</h2>
      <p>Torque is what makes things rotate. If force is a push or pull in a straight line, torque is a push or pull that makes something <strong>spin</strong>. The formula is straightforward:</p>

      <div class="formula-block">\\\\[\\\\tau = F \\\\times d \\\\quad \\\\text{(distance from the pivot point)}\\\\]</div>

      <p>Torque equals force times the distance from the pivot. It''s measured in Newton-meters (N·m). And here''s the key insight: <strong>the farther from the pivot you apply the force, the more torque you get</strong>.</p>

      <div class="callout callout-tip">
        <div class="callout-title">Think About It This Way</div>
        Why is it easier to loosen a bolt with a longer wrench? Because torque = force × distance. A longer wrench means a bigger distance from the pivot (the bolt), so you get more torque with the same effort. That''s why mechanics use breaker bars for really stubborn bolts &mdash; they''re just extra-long wrenches.
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Let''s Work Through One</div>
        You need 30 N·m of torque to loosen a bolt. Your wrench is 0.5 m long. How much force do you need?<br><br>
        \\\\(30 = F \\\\times 0.5\\\\)<br>
        \\\\(F = \\\\frac{30}{0.5} = \\\\textbf{60 N}\\\\)<br><br>
        Now what if you grabbed a wrench that''s 1 m long instead?<br>
        \\\\(F = \\\\frac{30}{1.0} = \\\\textbf{30 N}\\\\)<br><br>
        Double the wrench length, half the force needed. See the pattern?
      </div>

      <div class="callout callout-example">
        <div class="callout-title">Why Doors Have Handles on the Edge</div>
        Ever tried to push a door open near the hinge? It''s almost impossible. But push at the handle (far from the hinge) and it swings right open. Same force, but the handle is farther from the pivot &mdash; so you get way more torque. Door designers put handles at the edge for this exact reason.
      </div>

      <!-- ===== PRACTICE ===== -->
      <h2>Try It Yourself</h2>
      <div class="callout callout-example">
        <div class="callout-title">Practice Problems</div>
        <strong>1.</strong> A nutcracker cracks a nut. The hinge is at one end, the nut is between the hinge and your hand. What class of lever is this?<br>
        <em>Hint: What''s in the middle &mdash; fulcrum, load, or effort?</em><br><br>
        <strong>2.</strong> A 25 kg child sits 4 m from the fulcrum of a seesaw. How far from the fulcrum should a 50 kg child sit to balance?<br>
        <em>Hint: F1 × D1 = F2 × D2</em><br><br>
        <strong>3.</strong> A lever has an effort arm of 10 ft and a load arm of 2 ft. What is its mechanical advantage? If the load weighs 500 lbs, how much effort is needed?<br>
        <em>Hint: MA = effort arm / load arm</em><br><br>
        <strong>4.</strong> You need 50 N·m of torque. You have a 0.25 m wrench. How much force must you apply?<br>
        <em>Hint: &tau; = F × d</em>
      </div>

      <div class="callout callout-tip">
        <div class="callout-title">Answers</div>
        1. <strong>2nd class</strong> &mdash; the load (nut) is in the middle. L = 2nd class. Like a wheelbarrow.<br>
        2. \\\\(25 \\\\times 4 = 50 \\\\times d \\\\rightarrow d = 100/50 = \\\\textbf{2 m}\\\\)<br>
        3. \\\\(MA = 10/2 = 5\\\\). Effort = \\\\(500/5 = \\\\textbf{100 lbs}\\\\)<br>
        4. \\\\(F = 50/0.25 = \\\\textbf{200 N}\\\\) &mdash; that''s a lot of force! You''d want a longer wrench.
      </div>', 8)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (9, 'MECHANICAL COMPREHENSION', 'Gears & Pulleys', 'Gear direction, gear ratios, pulley systems, mechanical advantage', ARRAY['Gears','Pulleys','Ratios'], '<h1>Gears &amp; Pulleys</h1>
      <p class="lesson-subtitle">Gears and pulleys show up on nearly every OAR. Master the direction rules and ratio calculations.</p>

      <h2>Gear Direction Rules</h2>
      <ul>
        <li><strong>Adjacent gears</strong> always turn in <strong>opposite</strong> directions</li>
        <li>In a chain of gears: <strong>odd number</strong> of gears = first and last turn the <strong>same</strong> direction</li>
        <li><strong>Even number</strong> = first and last turn <strong>opposite</strong> directions</li>
      </ul>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Gear A turns clockwise. Adjacent Gear B turns: <strong>counterclockwise</strong><br><br>
        5 gears in a chain, first turns CW. Last gear turns: <strong>CW</strong> (5 is odd = same direction)
      </div>

      <h2>Gear Ratio Formula</h2>
      <div class="formula-block">\\\\[T_{1} \\\\times RPM_{1} = T_{2} \\\\times RPM_{2}\\\\]</div>
      <p>Where T = number of teeth, RPM = rotations per minute.</p>
      <div class="callout callout-tip">
        <div class="callout-title">Key Insight</div>
        <strong>Smaller gear = faster rotation.</strong> The gear with fewer teeth spins faster.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Gear A: 20 teeth at 100 RPM. Gear B: 50 teeth. B''s speed:<br>
        20 × 100 = 50 × RPM → RPM = 2000/50 = <strong>40 RPM</strong>
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example: Gear Train</div>
        A(10t) → B(30t) → C(15t). A spins at 300 RPM. C''s speed:<br>
        A→B: 10 × 300 = 30 × RPM<sub>B</sub> → RPM<sub>B</sub> = 100<br>
        B→C: 30 × 100 = 15 × RPM<sub>C</sub> → RPM<sub>C</sub> = <strong>200 RPM</strong>
      </div>

      <h2>Pulley Systems</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Types of Pulleys</div>
        <strong>Fixed pulley:</strong> MA = 1 (changes direction only, no force reduction)<br>
        <strong>Movable pulley:</strong> MA = 2 (halves the required force)<br>
        <strong>Block &amp; tackle:</strong> MA = number of rope segments supporting the load
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Fixed pulley, 100 lb load: Force needed = <strong>100 lbs</strong> (MA=1)<br><br>
        4 ropes supporting a 200 lb load: Force = 200/4 = <strong>50 lbs</strong>
      </div>

      <h2>The Golden Rule of Simple Machines</h2>
      <div class="callout callout-warning">
        <div class="callout-title">Never Forget</div>
        <strong>Force × Distance = Constant.</strong> You can reduce force, but you''ll always increase the distance you must pull/push. You never get something for nothing.
      </div>', 9)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (10, 'MECHANICAL COMPREHENSION', 'Energy, Work & Power', 'Work, kinetic energy, potential energy, conservation, power, inclined planes', ARRAY['Energy','Work','Power'], '<h1>Energy, Work &amp; Power</h1>
      <p class="lesson-subtitle">Understand the relationships between work, energy, and power. These concepts connect everything in mechanics.</p>

      <h2>Work</h2>
      <div class="formula-block">\\\\[W = F \\\\times d\\\\]</div>
      <p>Work equals force applied in the direction of motion times distance. Measured in <strong>Joules (J)</strong>.</p>
      <div class="callout callout-warning">
        <div class="callout-title">Key Point</div>
        If the force is <strong>perpendicular</strong> to the motion (like carrying a box horizontally &mdash; gravity pulls down), the work done by that force is <strong>zero</strong>.
      </div>

      <h2>Kinetic Energy</h2>
      <div class="formula-block">\\\\[KE = \\\\frac{1}{2}mv^{2}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        4 kg object at 5 m/s:<br>
        KE = ½ × 4 × 25 = <strong>50 J</strong>
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Most Tested Concept</div>
        <strong>Double the speed = 4× the kinetic energy!</strong><br>
        Because velocity is <em>squared</em>, doubling speed quadruples KE. This is why high-speed crashes are so devastating.
      </div>

      <h2>Potential Energy</h2>
      <div class="formula-block">\\\\[PE = mgh\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        10 kg lifted 5m (g = 10 m/s²):<br>
        PE = 10 × 10 × 5 = <strong>500 J</strong>
      </div>

      <h2>Conservation of Energy</h2>
      <div class="formula-block">\\\\[KE + PE = \\\\text{constant (no friction)}\\\\]</div>
      <p>Energy transforms between kinetic and potential but is never created or destroyed.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        2 kg object dropped from 20m (g = 10). Speed at bottom:<br>
        PE at top = KE at bottom<br>
        mgh = ½mv²<br>
        2(10)(20) = ½(2)v²<br>
        400 = v² → v = <strong>20 m/s</strong>
      </div>

      <h2>Power</h2>
      <div class="formula-block">\\\\[P = \\\\frac{W}{t}\\\\]</div>
      <p>Power is the <strong>rate</strong> of doing work. Measured in <strong>Watts</strong> (1 W = 1 J/s).</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        600 J of work done in 30 seconds:<br>
        P = 600/30 = <strong>20 W</strong>
      </div>

      <h2>Inclined Plane</h2>
      <div class="formula-block">\\\\[MA = \\\\frac{\\\\text{Length}}{\\\\text{Height}}\\\\]</div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Ramp is 10m long and 2m high:<br>
        MA = 10/2 = <strong>5</strong><br>
        You use 1/5 the force but travel 5× the distance.
      </div>', 10)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (11, 'MECHANICAL COMPREHENSION', 'Fluids & Pressure', 'Pressure, Pascal''s law, buoyancy, continuity, Bernoulli''s principle', ARRAY['Pressure','Hydraulics','Bernoulli'], '<h1>Fluids &amp; Pressure</h1>
      <p class="lesson-subtitle">Hydraulics, buoyancy, and fluid flow &mdash; the concepts that explain everything from submarines to airplane lift.</p>

      <h2>Pressure</h2>
      <div class="formula-block">\\\\[P = \\\\frac{F}{A}\\\\]</div>
      <p>Pressure is force distributed over an area. Measured in <strong>Pascals (Pa)</strong> or N/m².</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        200N over 4 m²:<br>
        P = 200/4 = <strong>50 Pa</strong>
      </div>

      <h2>Pascal''s Law (Hydraulics)</h2>
      <div class="formula-block">\\\\[\\\\frac{F_{1}}{A_{1}} = \\\\frac{F_{2}}{A_{2}}\\\\]</div>
      <p>Pressure is transmitted equally through an enclosed fluid. This is how hydraulic systems multiply force.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Small piston: 5 cm², 40N. Large piston: 25 cm². Force output:<br>
        40/5 = F/25 → F = 8 × 25 = <strong>200N</strong>
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Key Insight</div>
        Bigger area = bigger force output. But the small piston must travel a longer distance (golden rule of machines).
      </div>

      <h2>Buoyancy</h2>
      <p>An object floats if its <strong>average density is less than the fluid''s density</strong>.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A block is 60% submerged in water. Its density relative to water:<br>
        Density ratio = fraction submerged = <strong>0.6</strong><br>
        (Density = 0.6 × density of water)
      </div>

      <h2>Continuity Equation</h2>
      <div class="formula-block">\\\\[A_{1} \\\\times v_{1} = A_{2} \\\\times v_{2}\\\\]</div>
      <p>For incompressible fluids, the product of cross-sectional area and velocity is constant.</p>
      <div class="callout callout-tip">
        <div class="callout-title">Key Rule</div>
        <strong>Narrower pipe = faster flow.</strong> Think of putting your thumb over a garden hose.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Pipe area goes from 10 cm² to 5 cm². Initial velocity: 2 m/s.<br>
        10 × 2 = 5 × v → v = <strong>4 m/s</strong>
      </div>

      <h2>Bernoulli''s Principle</h2>
      <div class="callout callout-formula">
        <div class="callout-title">The Rule</div>
        <strong>Faster fluid = lower pressure.</strong><br>
        This is how airplane wings generate lift: air moves faster over the curved top, creating lower pressure above the wing.
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">OAR Favorite</div>
        Bernoulli questions are very common. If air speeds up, pressure <strong>decreases</strong>. Always.
      </div>', 11)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (12, 'MECHANICAL COMPREHENSION', 'Electricity Basics', 'Ohm''s law, series and parallel circuits, power', ARRAY['Ohm''s Law','Series','Parallel'], '<h1>Electricity Basics</h1>
      <p class="lesson-subtitle">Ohm''s law, circuit types, and electrical power. The OAR tests fundamental circuit analysis.</p>

      <h2>Ohm''s Law</h2>
      <div class="formula-block">\\\\[V = IR\\\\]</div>
      <p><strong>V</strong> = Voltage (Volts), <strong>I</strong> = Current (Amps), <strong>R</strong> = Resistance (Ohms)</p>
      <div class="callout callout-tip">
        <div class="callout-title">VIR Triangle</div>
        Cover what you want to find:<br>
        Cover V → V = IR<br>
        Cover I → I = V/R<br>
        Cover R → R = V/I
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        12V battery, 4Ω resistor:<br>
        I = V/R = 12/4 = <strong>3A</strong>
      </div>

      <h2>Series Circuits</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Series Rules</div>
        <strong>Resistance adds:</strong> R<sub>total</sub> = R₁ + R₂ + R₃<br>
        <strong>Current is the same</strong> through all components<br>
        <strong>One break = all die</strong> (like old Christmas lights)
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Resistors of 2Ω, 3Ω, 5Ω in series:<br>
        R<sub>total</sub> = 2 + 3 + 5 = <strong>10Ω</strong>
      </div>

      <h2>Parallel Circuits</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Parallel Rules</div>
        <strong>Reciprocals add:</strong> 1/R<sub>total</sub> = 1/R₁ + 1/R₂<br>
        <strong>Voltage is the same</strong> across all branches<br>
        <strong>One break = others still work</strong> (like modern house wiring)
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        Two 10Ω resistors in parallel:<br>
        1/R = 1/10 + 1/10 = 2/10<br>
        R = 10/2 = <strong>5Ω</strong>
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Shortcut for Two Equal Resistors</div>
        Two equal resistors in parallel: R<sub>total</sub> = R / 2. Three equal: R<sub>total</sub> = R / 3. And so on.
      </div>

      <h2>Electrical Power</h2>
      <div class="formula-block">\\\\[P = V \\\\times I\\\\]</div>
      <p>Power is measured in <strong>Watts (W)</strong>.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        120V, 2A device:<br>
        P = 120 × 2 = <strong>240 W</strong>
      </div>

      <h2>Series vs Parallel: Quick Reference</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Comparison</div>
        <strong>Series:</strong> One path for current. R adds up. Current same everywhere. One fails, all fail.<br>
        <strong>Parallel:</strong> Multiple paths. R decreases. Voltage same everywhere. One fails, rest work.
      </div>', 12)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (13, 'MECHANICAL COMPREHENSION', 'Momentum & Impulse', 'Linear momentum, impulse-momentum theorem, conservation of momentum, elastic and inelastic collisions', ARRAY['Momentum','Impulse','Collisions','Conservation'], '<h1>Momentum &amp; Impulse</h1>
      <p class="lesson-subtitle">Understand how objects transfer motion during collisions and why momentum is always conserved in closed systems.</p>

      <h2>Linear Momentum</h2>
      <p>Momentum is mass in motion. It is a <strong>vector quantity</strong> &mdash; it has both magnitude and direction.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Formula</div>
        \\\\(p = mv\\\\)<br>
        <strong>p</strong> = momentum (kg·m/s) &nbsp;|&nbsp; <strong>m</strong> = mass (kg) &nbsp;|&nbsp; <strong>v</strong> = velocity (m/s)
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Key Insight</div>
        A slow, heavy truck can have the same momentum as a fast, light car. Momentum depends on <strong>both</strong> mass and velocity.
      </div>

      <h2>Impulse</h2>
      <p>Impulse is the change in momentum caused by a force acting over time.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Impulse-Momentum Theorem</div>
        \\\\[F\\\\Delta t = m\\\\Delta v\\\\]
        Force × time = change in momentum. Units: Newton-seconds (N·s)
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A 2-kg block starts at rest. An 8N force is applied for 5 seconds.<br>
        Impulse = \\\\(F \\\\times \\\\Delta t = 8 \\\\times 5 =\\\\) <strong>40 N·s</strong><br>
        \\\\(\\\\Delta v = \\\\frac{F \\\\Delta t}{m} = \\\\frac{40}{2} =\\\\) <strong>20 m/s</strong>
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Why Airbags Work</div>
        Airbags increase the <strong>time</strong> of impact, which <strong>reduces the force</strong> for the same change in momentum. Same impulse, less damage.
      </div>

      <h2>Conservation of Momentum</h2>
      <p>In a <strong>closed system</strong> (no external forces), total momentum before a collision equals total momentum after.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Conservation Law</div>
        \\\\[p_{\\\\text{initial}} = p_{\\\\text{final}}\\\\]
        \\\\[m_1 v_1 + m_2 v_2 = m_1 v_1'' + m_2 v_2''\\\\]
      </div>

      <h2>Types of Collisions</h2>
      <p><strong>Elastic Collisions:</strong> Both kinetic energy AND momentum are conserved. Objects bounce off each other (e.g., billiard balls).</p>
      <p><strong>Inelastic Collisions:</strong> Only momentum is conserved. Objects may deform or stick together. In a <strong>perfectly inelastic</strong> collision, the objects combine into one mass.</p>
      <div class="callout callout-example">
        <div class="callout-title">Example: Perfectly Inelastic Collision</div>
        A 0.01-kg bullet traveling at 400 m/s embeds in a 10-kg block at rest.<br>
        \\\\(m_1 v_1 + m_2 v_2 = (m_1 + m_2) v_f\\\\)<br>
        \\\\(0.01 \\\\times 400 + 10 \\\\times 0 = (0.01 + 10) \\\\times v_f\\\\)<br>
        \\\\(4 = 10.01 \\\\times v_f\\\\)<br>
        \\\\(v_f \\\\approx\\\\) <strong>0.4 m/s</strong>
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Common Trap</div>
        Don''t confuse elastic and inelastic. On the OAR, if objects <strong>stick together</strong>, it''s perfectly inelastic. If they <strong>bounce</strong>, check whether KE is conserved to determine if it''s elastic.
      </div>', 13)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (14, 'MECHANICAL COMPREHENSION', 'Kinematics — Displacement, Velocity & Acceleration', 'Kinematic equations, projectile motion, uniform circular motion', ARRAY['Kinematics','Velocity','Acceleration','Projectile','Circular Motion'], '<h1>Kinematics &mdash; Displacement, Velocity &amp; Acceleration</h1>
      <p class="lesson-subtitle">Describe how objects move through space and time using the core kinematic equations.</p>

      <h2>Displacement, Velocity &amp; Acceleration</h2>
      <p><strong>Displacement</strong> (\\\\(\\\\Delta x\\\\)) is the change in position &mdash; a vector quantity (direction matters).</p>
      <div class="callout callout-formula">
        <div class="callout-title">Definitions</div>
        \\\\(\\\\Delta x = x_f - x_i\\\\) &nbsp;(displacement)<br>
        \\\\(v_{\\\\text{avg}} = \\\\frac{\\\\Delta x}{\\\\Delta t}\\\\) &nbsp;(average velocity, m/s)<br>
        \\\\(a = \\\\frac{\\\\Delta v}{\\\\Delta t}\\\\) &nbsp;(acceleration, m/s²)
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Distance vs. Displacement</div>
        Distance is total path traveled (always positive). Displacement is straight-line change in position (can be negative). A round trip has large distance but <strong>zero</strong> displacement.
      </div>

      <h2>Kinematic Equations (Constant Acceleration)</h2>
      <p>These four equations solve every constant-acceleration problem. Pick the one that matches your knowns and unknowns.</p>
      <div class="callout callout-formula">
        <div class="callout-title">The Big Four</div>
        \\\\[x_f = x_i + v_i t + \\\\tfrac{1}{2}at^2\\\\]
        \\\\[v_f = v_i + at\\\\]
        \\\\[v_f^2 = v_i^2 + 2a\\\\Delta x\\\\]
        \\\\[\\\\Delta x = \\\\frac{(v_f + v_i)}{2} \\\\cdot t\\\\]
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A car starts from rest and accelerates at 3 m/s² for 8 seconds. How far does it travel?<br>
        \\\\(x = 0 + 0 + \\\\tfrac{1}{2}(3)(8^2) = \\\\tfrac{1}{2}(3)(64) =\\\\) <strong>96 m</strong>
      </div>

      <h2>Projectile Motion</h2>
      <p>A projectile has <strong>two independent motions</strong>: constant velocity horizontally and constant acceleration (gravity) vertically.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Projectile Components</div>
        Horizontal: \\\\(v_{0x} = v_0 \\\\cos\\\\theta\\\\) &nbsp;(constant, no acceleration)<br>
        Vertical: \\\\(v_{0y} = v_0 \\\\sin\\\\theta\\\\) &nbsp;(accelerated by \\\\(g = 9.8\\\\) m/s² downward)
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Key Point</div>
        At the <strong>peak</strong> of a projectile''s arc, the vertical velocity is <strong>zero</strong> but horizontal velocity is <strong>unchanged</strong>. The object is NOT stationary at the top.
      </div>

      <h2>Uniform Circular Motion</h2>
      <p>An object moving in a circle at constant speed is still <strong>accelerating</strong> because its direction is constantly changing.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Centripetal Acceleration</div>
        \\\\[a_c = \\\\frac{v^2}{r}\\\\]
        The acceleration always points <strong>toward the center</strong> of the circle.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A car rounds a curve of radius 50m at 20 m/s.<br>
        \\\\(a_c = \\\\frac{20^2}{50} = \\\\frac{400}{50} =\\\\) <strong>8 m/s²</strong> toward the center
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">OAR Tip</div>
        Centripetal force is not a new force &mdash; it is the <strong>net inward force</strong> (friction, tension, gravity, etc.) that keeps an object in a circular path.
      </div>', 14)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (15, 'MECHANICAL COMPREHENSION', 'Gas Laws', 'Ideal gas law, Boyle''s law, Charles''s law, combined gas law, Avogadro''s law', ARRAY['Gas Laws','Ideal Gas','Boyle','Charles','PV=nRT'], '<h1>Gas Laws</h1>
      <p class="lesson-subtitle">Understand how pressure, volume, and temperature relate in gases &mdash; from tire pressure on a hot day to scuba diving physics.</p>

      <h2>The Ideal Gas Law</h2>
      <p>The master equation that connects all gas properties:</p>
      <div class="callout callout-formula">
        <div class="callout-title">Ideal Gas Law</div>
        \\\\[PV = nRT\\\\]
        <strong>P</strong> = pressure &nbsp;|&nbsp; <strong>V</strong> = volume &nbsp;|&nbsp; <strong>n</strong> = number of moles &nbsp;|&nbsp; <strong>R</strong> = gas constant &nbsp;|&nbsp; <strong>T</strong> = temperature (Kelvin)
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Temperature Must Be Kelvin</div>
        Always convert to Kelvin before using any gas law. \\\\(K = °C + 273\\\\). If a problem gives Celsius, convert first!
      </div>

      <h2>Boyle''s Law (Constant Temperature)</h2>
      <p>When temperature stays the same, pressure and volume are <strong>inversely</strong> related.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Boyle''s Law</div>
        \\\\[P_1 V_1 = P_2 V_2\\\\]
        Pressure goes up → volume goes down (and vice versa)
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A gas occupies 5.0L at 1.0 atm. What volume at 2.0 atm?<br>
        \\\\(1.0 \\\\times 5.0 = 2.0 \\\\times V_2\\\\)<br>
        \\\\(V_2 = \\\\frac{5.0}{2.0} =\\\\) <strong>2.5L</strong><br>
        Doubled pressure = half the volume.
      </div>

      <h2>Charles''s Law (Constant Pressure)</h2>
      <p>When pressure stays the same, volume and temperature are <strong>directly</strong> related.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Charles''s Law</div>
        \\\\[\\\\frac{V_1}{T_1} = \\\\frac{V_2}{T_2}\\\\]
        Temperature goes up → volume goes up
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A gas occupies 10.0L at 200K. What volume at 300K?<br>
        \\\\(\\\\frac{10.0}{200} = \\\\frac{V_2}{300}\\\\)<br>
        \\\\(V_2 = \\\\frac{10.0 \\\\times 300}{200} =\\\\) <strong>15.0L</strong>
      </div>

      <h2>Combined Gas Law</h2>
      <p>When both temperature and pressure change, use the combined law:</p>
      <div class="callout callout-formula">
        <div class="callout-title">Combined Gas Law</div>
        \\\\[\\\\frac{P_1 V_1}{T_1} = \\\\frac{P_2 V_2}{T_2}\\\\]
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">How to Remember</div>
        Boyle''s and Charles''s laws are just special cases of the combined gas law. Hold T constant → Boyle''s. Hold P constant → Charles''s.
      </div>

      <h2>Avogadro''s Law</h2>
      <p>At constant temperature and pressure, volume is directly proportional to the number of moles of gas.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Avogadro''s Law</div>
        \\\\[\\\\frac{V}{n} = \\\\text{constant}\\\\]
        More gas molecules → more volume (at same T and P)
      </div>', 15)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (16, 'MECHANICAL COMPREHENSION', 'Heat Transfer', 'Conduction, convection, radiation, states of matter, phase changes, phase diagrams', ARRAY['Heat Transfer','Conduction','Convection','Radiation','Phase Changes'], '<h1>Heat Transfer</h1>
      <p class="lesson-subtitle">How thermal energy moves between objects and how matter changes state &mdash; essential for understanding engines, cooling, and weather.</p>

      <h2>Three Modes of Heat Transfer</h2>
      <p>Heat always flows from <strong>hot to cold</strong>. There are exactly three ways this happens:</p>

      <h3>Conduction (Direct Contact)</h3>
      <p>Heat transfers through a material by molecular collisions. No bulk movement of matter.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Fourier''s Law of Conduction</div>
        \\\\[q = kA\\\\frac{\\\\Delta T}{\\\\Delta x}\\\\]
        <strong>q</strong> = heat flow rate &nbsp;|&nbsp; <strong>k</strong> = thermal conductivity &nbsp;|&nbsp; <strong>A</strong> = cross-sectional area &nbsp;|&nbsp; \\\\(\\\\Delta T / \\\\Delta x\\\\) = temperature gradient
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Good vs. Poor Conductors</div>
        <strong>Metals</strong> (copper, aluminum, iron) are excellent conductors. <strong>Wood, rubber, air</strong> are poor conductors (insulators). That''s why pot handles are wooden.
      </div>

      <h3>Convection (Fluid Movement)</h3>
      <p>Heat transfers through the <strong>bulk movement of fluid</strong> (liquid or gas). Hot fluid rises, cool fluid sinks.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Convection Equation</div>
        \\\\[q = hA\\\\Delta T\\\\]
        <strong>h</strong> = convection coefficient &nbsp;|&nbsp; <strong>Free convection</strong> = natural (hot air rising) &nbsp;|&nbsp; <strong>Forced convection</strong> = fan or pump
      </div>

      <h3>Radiation (Electromagnetic Waves)</h3>
      <p>Heat transfers through electromagnetic waves. <strong>No medium needed</strong> &mdash; this is how the sun heats the Earth across the vacuum of space.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Stefan-Boltzmann Law</div>
        \\\\[q = e\\\\sigma A T^4\\\\]
        <strong>e</strong> = emissivity (0 to 1) &nbsp;|&nbsp; \\\\(\\\\sigma\\\\) = Stefan-Boltzmann constant<br>
        Dark surfaces have <strong>high emissivity</strong> (absorb and emit more radiation). Shiny surfaces reflect radiation.
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example: Identifying the Mode</div>
        &bull; Touching a hot stove → <strong>Conduction</strong><br>
        &bull; Warm air rising from a heater → <strong>Convection</strong><br>
        &bull; Feeling warmth from a campfire across the room → <strong>Radiation</strong>
      </div>

      <h2>States of Matter &amp; Phase Changes</h2>
      <p>Matter exists in four states, each with different properties:</p>
      <ul>
        <li><strong>Solid</strong> &mdash; fixed shape and fixed volume</li>
        <li><strong>Liquid</strong> &mdash; no fixed shape, fixed volume</li>
        <li><strong>Gas</strong> &mdash; no fixed shape, no fixed volume</li>
        <li><strong>Plasma</strong> &mdash; ionized gas (stars, lightning)</li>
      </ul>
      <div class="callout callout-formula">
        <div class="callout-title">Phase Change Names</div>
        Solid → Liquid = <strong>Melting</strong> &nbsp;|&nbsp; Liquid → Solid = <strong>Freezing</strong><br>
        Liquid → Gas = <strong>Vaporization</strong> &nbsp;|&nbsp; Gas → Liquid = <strong>Condensation</strong><br>
        Solid → Gas = <strong>Sublimation</strong> &nbsp;|&nbsp; Gas → Solid = <strong>Deposition</strong>
      </div>

      <h2>Phase Diagrams</h2>
      <p>A phase diagram plots <strong>pressure vs. temperature</strong> to show which state matter is in at each combination.</p>
      <div class="callout callout-tip">
        <div class="callout-title">Key Feature: Triple Point</div>
        The <strong>triple point</strong> is where all three phases (solid, liquid, gas) coexist simultaneously. Every pure substance has exactly one triple point.
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">OAR Trap</div>
        During a phase change, <strong>temperature stays constant</strong> even though heat is being added. The energy goes into breaking molecular bonds, not raising temperature. This is called <strong>latent heat</strong>.
      </div>', 16)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

INSERT INTO lessons (id, section, title, description, tags, content_html, sort_order)
VALUES (17, 'MECHANICAL COMPREHENSION', 'Magnetism & Advanced Electrical Components', 'Magnets, magnetic fields, electromagnets, capacitors, transformers, motors, generators, diodes', ARRAY['Magnetism','Electromagnets','Capacitors','Transformers','Motors'], '<h1>Magnetism &amp; Advanced Electrical Components</h1>
      <p class="lesson-subtitle">From permanent magnets to electromagnets, capacitors, and transformers &mdash; the components that power modern technology.</p>

      <h2>Magnets &amp; Magnetic Fields</h2>
      <p>Every magnet has a <strong>north pole</strong> and a <strong>south pole</strong>. Like poles repel; opposite poles attract.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Magnetic Field Rules</div>
        &bull; Magnetic field lines run from <strong>north to south</strong> outside the magnet<br>
        &bull; Moving electric charges (current) produce magnetic fields<br>
        &bull; <strong>Unpaired electrons</strong> in atoms create magnetic materials
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">Three Types of Magnetic Materials</div>
        <strong>Ferromagnetic</strong> (strongly attracted): iron, cobalt, nickel &mdash; can become permanent magnets<br>
        <strong>Paramagnetic</strong> (weakly attracted): aluminum, platinum &mdash; only magnetic in external field<br>
        <strong>Diamagnetic</strong> (not attracted, slightly repelled): copper, gold, water &mdash; no magnetic field
      </div>

      <h2>Electromagnets</h2>
      <p>An electromagnet is created by running <strong>current through a coiled wire</strong> (solenoid), often wrapped around an <strong>iron core</strong> to amplify the field.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Electromagnet Properties</div>
        &bull; <strong>No current = no magnetism</strong> (can be switched on/off)<br>
        &bull; More coils = stronger field<br>
        &bull; More current = stronger field<br>
        &bull; Iron core = much stronger field
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example Applications</div>
        &bull; <strong>Doorbells</strong> &mdash; electromagnet pulls a striker to ring the bell<br>
        &bull; <strong>Junkyard cranes</strong> &mdash; powerful electromagnets pick up and drop scrap metal<br>
        &bull; <strong>MRI machines</strong> &mdash; superconducting electromagnets create imaging fields
      </div>

      <h2>Capacitors</h2>
      <p>Capacitors store energy in an <strong>electric field</strong> between two conductive plates separated by an insulator (dielectric).</p>
      <div class="callout callout-formula">
        <div class="callout-title">Capacitor Formulas</div>
        Capacitance: \\\\(C = \\\\frac{Q}{V}\\\\) &nbsp;(units: Farads, F)<br>
        Energy stored: \\\\(E = \\\\frac{1}{2}CV^2\\\\)<br>
        <strong>C</strong> = capacitance &nbsp;|&nbsp; <strong>Q</strong> = charge &nbsp;|&nbsp; <strong>V</strong> = voltage
      </div>
      <div class="callout callout-warning">
        <div class="callout-title">Key Difference</div>
        <strong>Batteries</strong> store energy chemically and release it slowly. <strong>Capacitors</strong> store energy in electric fields and can release it almost instantly (camera flash, defibrillators).
      </div>

      <h2>Transformers</h2>
      <p>Transformers change voltage levels using electromagnetic induction. They only work with <strong>AC (alternating current)</strong>.</p>
      <div class="callout callout-formula">
        <div class="callout-title">Transformer Types</div>
        <strong>Step-up transformer:</strong> increases voltage (more turns on secondary coil)<br>
        <strong>Step-down transformer:</strong> decreases voltage (fewer turns on secondary coil)<br><br>
        \\\\(\\\\frac{V_1}{V_2} = \\\\frac{N_1}{N_2}\\\\) &nbsp;(voltage ratio = turns ratio)
      </div>
      <div class="callout callout-example">
        <div class="callout-title">Example</div>
        A transformer has 100 primary turns and 500 secondary turns. Input: 120V.<br>
        \\\\(\\\\frac{120}{V_2} = \\\\frac{100}{500}\\\\)<br>
        \\\\(V_2 = \\\\frac{120 \\\\times 500}{100} =\\\\) <strong>600V</strong> (step-up)
      </div>

      <h2>Motors, Generators &amp; Diodes</h2>
      <div class="callout callout-formula">
        <div class="callout-title">Energy Conversion Devices</div>
        <strong>Motor:</strong> Electrical energy → Mechanical energy (motion). Uses current in a magnetic field to spin a shaft.<br>
        <strong>Generator:</strong> Mechanical energy → Electrical energy. Spinning a coil in a magnetic field induces current (opposite of a motor).<br>
        <strong>Diode:</strong> Allows current to flow in <strong>one direction only</strong> (electrical "valve"). LED is a common type that also emits light.
      </div>
      <div class="callout callout-tip">
        <div class="callout-title">OAR Memory Trick</div>
        <strong>Motors</strong> = electricity makes things <strong>M</strong>ove.<br>
        <strong>Generators</strong> = movement <strong>G</strong>enerates electricity.<br>
        They are essentially the same device running in reverse.
      </div>', 17)
ON CONFLICT (id) DO UPDATE SET content_html = EXCLUDED.content_html, title = EXCLUDED.title;

