VALUES ('MC1', 'Mechanical', 'Forces', 'A 5 kg object has a net force of 20N applied. What is its acceleration?', NULL, ARRAY['4 m/s²','100 m/s²','15 m/s²','25 m/s²'], 0, 'F = ma → a = F/m = 20/5 = 4 m/s².', 2)
