VALUES ('MC2', 'Mechanical', 'Forces', 'An object moves at constant velocity. What is the net force acting on it?', NULL, ARRAY['Zero','Equal to its weight','Depends on speed','Cannot be determined'], 0, 'Newton''s 1st Law: constant velocity means balanced forces, so net force = 0.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC3', 'Mechanical', 'Forces', 'A 2 kg object is dropped. What is its velocity after 3 seconds? (g = 10 m/s²)', NULL, ARRAY['30 m/s','60 m/s','20 m/s','6 m/s'], 0, 'v = gt = 10 × 3 = 30 m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC4', 'Mechanical', 'Forces', 'A 50N force pushes right, 20N friction pushes left. Net force?', NULL, ARRAY['30N right','70N right','30N left','20N right'], 0, 'Net = 50 - 20 = 30N in the direction of the larger force (right).', 2)
