INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC5', 'Mechanical', 'Forces', 'You push a wall with 15N. How much force does the wall exert on you?', NULL, ARRAY['15N','0N','30N','7.5N'], 0, 'Newton''s 3rd Law: the wall pushes back with equal force (15N) in the opposite direction.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC32', 'Mechanical', 'Forces', 'A 1000 kg car accelerates from 0 to 20 m/s in 10 seconds. What force is required?', NULL, ARRAY['2000N','200N','20000N','10000N'], 0, 'a = 20/10 = 2 m/s². F = ma = 1000 × 2 = 2000N.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC6', 'Mechanical', 'Levers', 'A 40 kg weight sits 3m from the fulcrum. Where must a 60 kg weight sit to balance?', NULL, ARRAY['2m','3m','4m','1.5m'], 0, 'F₁D₁ = F₂D₂ → 40 × 3 = 60 × D → D = 120/60 = 2m.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

