VALUES ('MC7', 'Mechanical', 'Levers', 'What class of lever is a wheelbarrow?', NULL, ARRAY['2nd class','1st class','3rd class','Not a lever'], 0, 'Wheelbarrow: load in the middle (between fulcrum at wheel and effort at handles) = 2nd class.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC8', 'Mechanical', 'Levers', 'A lever has an effort arm of 8 ft and load arm of 2 ft. What is the mechanical advantage?', NULL, ARRAY['4','6','2','10'], 0, 'MA = effort arm / load arm = 8/2 = 4.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC9', 'Mechanical', 'Levers', 'What class of lever are tweezers?', NULL, ARRAY['3rd class','1st class','2nd class','Not a lever'], 0, 'Tweezers: effort (your fingers) in the middle = 3rd class. FLE: 1st=Fulcrum, 2nd=Load, 3rd=Effort.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC10', 'Mechanical', 'Levers', 'You need 30 N·m of torque. Your wrench is 0.5m long. How much force?', NULL, ARRAY['60N','15N','30N','150N'], 0, 'Torque = F × d → 30 = F × 0.5 → F = 60N.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC34', 'Mechanical', 'Levers', 'How much force to lift 300 lbs with a lever? Effort arm = 6ft, load arm = 2ft.', NULL, ARRAY['100 lbs','150 lbs','50 lbs','200 lbs'], 0, 'F × 6 = 300 × 2 → F = 600/6 = 100 lbs.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

