INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC16', 'Mechanical', 'Gears & Pulleys', 'Gear train: A(10t) → B(30t) → C(15t). A at 300 RPM. What is C''s speed?', NULL, ARRAY['200 RPM','100 RPM','150 RPM','600 RPM'], 0, 'A→B: 10×300 = 30×RPM<sub>B</sub> → RPM<sub>B</sub> = 100. B→C: 30×100 = 15×RPM<sub>C</sub> → RPM<sub>C</sub> = 200 RPM.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC17', 'Mechanical', 'Energy', 'A 4 kg object moves at 5 m/s. What is its kinetic energy?', NULL, ARRAY['50 J','100 J','20 J','10 J'], 0, 'KE = ½mv² = ½(4)(25) = 50 J.', 2)
