INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC18', 'Mechanical', 'Energy', 'If you double an object''s speed, what happens to its kinetic energy?', NULL, ARRAY['Quadruples','Doubles','Triples','Stays the same'], 0, 'KE = ½mv². Speed is squared, so doubling speed → 2² = 4× the KE.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC19', 'Mechanical', 'Energy', 'A 10 kg mass is lifted 5m. What is its potential energy? (g = 10)', NULL, ARRAY['500 J','50 J','100 J','250 J'], 0, 'PE = mgh = 10 × 10 × 5 = 500 J.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC20', 'Mechanical', 'Energy', 'A ramp is 10m long and 2m high. What is its mechanical advantage?', NULL, ARRAY['5','2','10','0.2'], 0, 'MA of inclined plane = length/height = 10/2 = 5.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC21', 'Mechanical', 'Energy', '600 J of work done in 30 seconds. What is the power?', NULL, ARRAY['20 W','200 W','18000 W','0.05 W'], 0, 'P = W/t = 600/30 = 20 W.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC31', 'Mechanical', 'Energy', 'A 2 kg object falls from 20m. What is its speed at the bottom? (g = 10)', NULL, ARRAY['20 m/s','40 m/s','10 m/s','200 m/s'], 0, 'PE = KE → mgh = ½mv² → v² = 2gh = 2(10)(20) = 400 → v = 20 m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC22', 'Mechanical', 'Fluids', '200N force over 4 m² area. What is the pressure?', NULL, ARRAY['50 Pa','800 Pa','196 Pa','4 Pa'], 0, 'P = F/A = 200/4 = 50 Pa.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC23', 'Mechanical', 'Fluids', 'Hydraulic system: small piston 5 cm², large piston 25 cm². 40N applied. Output force?', NULL, ARRAY['200N','8N','1000N','40N'], 0, 'Pascal''s law: F₁/A₁ = F₂/A₂ → 40/5 = F/25 → F = 200N.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC24', 'Mechanical', 'Fluids', 'A block is 60% submerged in water. What is its density relative to water?', NULL, ARRAY['0.6','0.4','1.6','1.0'], 0, 'Density ratio equals fraction submerged. 60% submerged → density = 0.6 × water density.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC25', 'Mechanical', 'Fluids', 'A pipe narrows from 10 cm² to 5 cm². Water enters at 2 m/s. Exit velocity?', NULL, ARRAY['4 m/s','1 m/s','2 m/s','10 m/s'], 0, 'Continuity: A₁v₁ = A₂v₂ → 10 × 2 = 5 × v → v = 4 m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC26', 'Mechanical', 'Electricity', 'A 12V battery powers a 4Ω resistor. What is the current?', NULL, ARRAY['3A','48A','0.33A','8A'], 0, 'Ohm''s law: I = V/R = 12/4 = 3A.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC27', 'Mechanical', 'Electricity', 'Three resistors (2Ω, 3Ω, 5Ω) in series. Total resistance?', NULL, ARRAY['10Ω','0.97Ω','30Ω','3.33Ω'], 0, 'Series: R<sub>total</sub> = R₁ + R₂ + R₃ = 2 + 3 + 5 = 10Ω.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC28', 'Mechanical', 'Electricity', 'Two 10Ω resistors in parallel. Total resistance?', NULL, ARRAY['5Ω','20Ω','10Ω','0.2Ω'], 0, 'Parallel: 1/R = 1/10 + 1/10 = 2/10. R = 10/2 = 5Ω. Shortcut: equal resistors in parallel = R/n.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC29', 'Mechanical', 'Electricity', 'In a series circuit, one bulb burns out. What happens?', NULL, ARRAY['All bulbs go out','Other bulbs get brighter','Nothing changes','Only adjacent bulbs go out'], 0, 'Series circuit: one path for current. If one element breaks, the circuit is open and all go out.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC30', 'Mechanical', 'Electricity', 'A device uses 120V and draws 2A. What is its power?', NULL, ARRAY['240W','60W','122W','0.017W'], 0, 'P = V × I = 120 × 2 = 240W.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC33', 'Mechanical', 'Electricity', 'According to Bernoulli''s principle, when air speeds up, what happens to pressure?', NULL, ARRAY['Pressure decreases','Pressure increases','Pressure stays the same','Pressure doubles'], 0, 'Bernoulli''s principle: faster fluid = lower pressure. This is how airplane wings generate lift.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC35', 'Mechanical', 'Momentum & Impulse', 'A 5-kg object moves at 10 m/s. What is its momentum?', NULL, ARRAY['50 kg·m/s','15 kg·m/s','2 kg·m/s','500 kg·m/s'], 0, 'p = mv = 5 × 10 = 50 kg·m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC36', 'Mechanical', 'Momentum & Impulse', 'A force of 20 N acts on an object for 3 seconds. What impulse does it receive?', NULL, ARRAY['60 N·s','23 N·s','6.67 N·s','17 N·s'], 0, 'Impulse J = FΔt = 20 × 3 = 60 N·s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC37', 'Mechanical', 'Momentum & Impulse', 'A 0.5-kg ball moving at 8 m/s collides with a stationary 1.5-kg block and they stick together. What is the final velocity?', NULL, ARRAY['2 m/s','4 m/s','8 m/s','1 m/s'], 0, 'Conservation of momentum: m₁v₁ = (m₁+m₂)v<sub>f</sub> → 0.5×8 = 2×v → v = 2 m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC38', 'Mechanical', 'Momentum & Impulse', 'In a perfectly elastic collision, which quantities are conserved?', NULL, ARRAY['Both momentum and kinetic energy','Only momentum','Only kinetic energy','Neither'], 0, 'Elastic collisions conserve BOTH momentum and kinetic energy. Inelastic collisions only conserve momentum.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC39', 'Mechanical', 'Momentum & Impulse', 'A 2-kg cart moving at 6 m/s collides with a 4-kg cart at rest. They stick together. What is the final velocity?', NULL, ARRAY['2 m/s','3 m/s','6 m/s','4 m/s'], 0, 'm₁v₁ = (m₁+m₂)v<sub>f</sub> → 2×6 = 6×v → v = 12/6 = 2 m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC40', 'Mechanical', 'Kinematics', 'An object starts from rest and accelerates at 4 m/s² for 5 seconds. What is its final velocity?', NULL, ARRAY['20 m/s','9 m/s','1.25 m/s','100 m/s'], 0, 'v = v₀ + at = 0 + 4×5 = 20 m/s.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC41', 'Mechanical', 'Kinematics', 'A ball is thrown upward at 30 m/s (g = 10 m/s²). How long until it stops rising?', NULL, ARRAY['3 seconds','30 seconds','0.33 seconds','6 seconds'], 0, 'At the top, v = 0. t = v₀/g = 30/10 = 3 seconds.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC42', 'Mechanical', 'Kinematics', 'An object starts from rest and accelerates at 2 m/s² for 10 seconds. How far does it travel?', NULL, ARRAY['100 m','20 m','200 m','50 m'], 0, 'd = ½at² = ½ × 2 × 10² = ½ × 2 × 100 = 100 m.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC43', 'Mechanical', 'Kinematics', 'A car traveling at 20 m/s brakes to a stop over 50 m. What is the acceleration?', NULL, ARRAY['-4 m/s²','-2 m/s²','4 m/s²','-8 m/s²'], 0, 'v² = v₀² + 2ad → 0 = 400 + 2a(50) → a = -400/100 = -4 m/s².', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC44', 'Mechanical', 'Kinematics', 'In uniform circular motion, the centripetal acceleration is directed:', NULL, ARRAY['Toward the center of the circle','Away from the center','Tangent to the circle','In the direction of motion'], 0, 'Centripetal means ''center-seeking.'' The acceleration always points toward the center of the circular path.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC45', 'Mechanical', 'Gas Laws', 'A gas occupies 4 L at 2 atm. If pressure increases to 8 atm at constant temperature, what is the new volume?', NULL, ARRAY['1 L','2 L','16 L','32 L'], 0, 'Boyle''s Law: P₁V₁ = P₂V₂ → 2×4 = 8×V → V = 8/8 = 1 L.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC46', 'Mechanical', 'Gas Laws', 'A gas at 300 K has a volume of 6 L. If heated to 600 K at constant pressure, what is the new volume?', NULL, ARRAY['12 L','3 L','6 L','1200 L'], 0, 'Charles''s Law: V₁/T₁ = V₂/T₂ → 6/300 = V/600 → V = 12 L.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC47', 'Mechanical', 'Gas Laws', 'What does the ideal gas law state?', NULL, ARRAY['PV = nRT','P = nRT/V²','PV² = nRT','P/V = nRT'], 0, 'The ideal gas law is PV = nRT, where P = pressure, V = volume, n = moles, R = gas constant, T = temperature.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC48', 'Mechanical', 'Gas Laws', 'According to Boyle''s Law, pressure and volume are:', NULL, ARRAY['Inversely related at constant temperature','Directly related at constant temperature','Unrelated','Inversely related at constant pressure'], 0, 'Boyle''s Law: P₁V₁ = P₂V₂. As pressure increases, volume decreases (inverse relationship) at constant temperature.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC49', 'Mechanical', 'Heat Transfer', 'Which type of heat transfer requires no medium (can travel through a vacuum)?', NULL, ARRAY['Radiation','Conduction','Convection','All require a medium'], 0, 'Radiation transfers energy via electromagnetic waves and does not need a medium — it can travel through the vacuum of space.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC50', 'Mechanical', 'Heat Transfer', 'A metal spoon in hot soup gets hot at the handle. This is an example of:', NULL, ARRAY['Conduction','Convection','Radiation','Evaporation'], 0, 'Conduction: heat transfer through direct contact between molecules. The heat travels through the solid spoon.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC51', 'Mechanical', 'Heat Transfer', 'Warm air rising from a heater is an example of:', NULL, ARRAY['Convection','Conduction','Radiation','Insulation'], 0, 'Convection: heat transfer through fluid (liquid or gas) movement. Warm air rises, cool air sinks, creating a current.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC52', 'Mechanical', 'Heat Transfer', 'At what point on a phase diagram do solid, liquid, and gas coexist in equilibrium?', NULL, ARRAY['Triple point','Boiling point','Critical point','Freezing point'], 0, 'The triple point is the unique temperature and pressure where all three phases of a substance coexist in equilibrium.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC53', 'Mechanical', 'Magnetism', 'What happens when two north poles of magnets are brought together?', NULL, ARRAY['They repel','They attract','Nothing happens','They demagnetize'], 0, 'Like poles (N-N or S-S) repel each other. Opposite poles (N-S) attract.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC54', 'Mechanical', 'Magnetism', 'Which of the following materials are ferromagnetic?', NULL, ARRAY['Iron, cobalt, and nickel','Copper, silver, and gold','Aluminum, zinc, and tin','Wood, plastic, and glass'], 0, 'Iron, cobalt, and nickel are the three naturally ferromagnetic elements — they can be strongly magnetized.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC55', 'Mechanical', 'Magnetism', 'What is the primary function of a transformer?', NULL, ARRAY['To increase or decrease voltage','To store electrical energy','To convert AC to DC','To measure current'], 0, 'Transformers change voltage levels using electromagnetic induction. Step-up increases voltage; step-down decreases it. V₁/V₂ = N₁/N₂.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MC56', 'Mechanical', 'Magnetism', 'A diode allows current to flow in:', NULL, ARRAY['One direction only','Both directions equally','Neither direction','Only when heated'], 0, 'A diode is a one-way valve for current. It allows flow in the forward direction and blocks it in reverse.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M1', 'Math', 'Word Problems', 'Haley''s violin instructor insists she practice a minimum of 3.5 hours per week. If she practices 45 minutes on both Sunday and Monday, 25 minutes on both Tuesday and Wednesday, how many minutes does she have left to practice?', NULL, ARRAY['70 minutes','75 minutes','80 minutes','85 minutes'], 0, '3.5 hours = 210 minutes. She practiced 45+45+25+25 = 140 minutes. 210 - 140 = 70 minutes remaining.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M2', 'Math', 'Algebra', 'Simplify: (2x⁴)³ + 2(y⁵)⁵', NULL, ARRAY['8x¹² + 2y²⁵','6x⁷ + 2y¹⁰','6x¹² + 2y²⁵','8x⁶⁴ + 2y³¹²⁵'], 0, '(2x⁴)³ = 2³·(x⁴)³ = 8x¹². 2(y⁵)⁵ = 2y²⁵. Answer: 8x¹² + 2y²⁵.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M3', 'Math', 'Geometry', 'If the ratio of the measures of the three angles in a triangle are 2:6:10, what is the actual measure of the smallest angle?', NULL, ARRAY['20 degrees','40 degrees','60 degrees','80 degrees'], 0, 'Total parts = 2+6+10 = 18. 180°/18 = 10° per part. Smallest = 2×10 = 20°.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M4', 'Math', 'Algebra', 'A plot of land has a width of w and a length of 2w+3. If the plot has an area of 90 square feet, what is the value of w?', NULL, ARRAY['6 feet','5 feet','15 feet','15/2 feet'], 0, 'w(2w+3) = 90 → 2w²+3w-90 = 0. Factoring: (2w+15)(w-6) = 0. w = 6.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M5', 'Math', 'Geometry', 'Connor has a fish tank that is a rectangular prism with length 7 inches and width 5 inches. It holds 210 cubic inches of water. What is the height?', NULL, ARRAY['6 inches','5 inches','17.5 inches','10 inches'], 0, 'V = lwh → 210 = 7×5×h → h = 210/35 = 6 inches.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M6', 'Math', 'Algebra', 'If 2x² = -4x² + 216, which of the following is a possible value of x?', NULL, ARRAY['6','4','5','7'], 0, '6x² = 216 → x² = 36 → x = ±6. So 6 is a possible value.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M7', 'Math', 'Geometry', 'The perimeter of a square is 24 m. What is its area?', NULL, ARRAY['36 m²','24 m²','30 m²','42 m²'], 0, 'Side = 24/4 = 6m. Area = 6² = 36 m².', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M8', 'Math', 'Word Problems', 'Mr. Foster wants to carpet his 27 ft by 18 ft playroom. Carpet costs $14 per square yard. What is the price?', NULL, ARRAY['$756','$486','$1,260','$2,268'], 0, 'Convert to yards: 27/3=9, 18/3=6. Area = 9×6 = 54 sq yards. Cost = 54×$14 = $756.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M9', 'Math', 'Arithmetic', 'Alicia rolls a standard six-sided die. What is the probability she rolls a number greater than or equal to 3?', NULL, ARRAY['2/3','5/6','3/5','3/4'], 0, 'Numbers ≥ 3: {3,4,5,6} = 4 outcomes. P = 4/6 = 2/3.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M10', 'Math', 'Algebra', 'A boat rental company charges $15 daily fee and $4 per hour. Which equation calculates total fee y for x hours?', NULL, ARRAY['y = 4x + 15','y = 15x + 4','x = 4y + 15','x = 15y + 4'], 0, '$15 flat + $4 per hour × x hours = y = 4x + 15.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M11', 'Math', 'Word Problems', 'Bruce is attending a conference 827 km away. Traveling at 64 km/hour, approximately how long will it take?', NULL, ARRAY['13 hours','5 hours','9 hours','17 hours'], 0, 'Time = Distance/Rate = 827/64 ≈ 12.9 ≈ 13 hours.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M12', 'Math', 'Word Problems', 'Jackson can decorate a cake in 3 hours. Eli can do it in 2 hours. Working together, how long will it take?', NULL, ARRAY['1.2 hours','0.8 hours','1.5 hours','1.8 hours'], 0, '1/3 + 1/2 = 5/6 per hour. Time = 6/5 = 1.2 hours.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M13', 'Math', 'Algebra', 'Solve for x by factoring: 2x² - 7x = x² - 12', NULL, ARRAY['x = 3, x = 4','x = -3, x = -4','x = 3, x = -4','x = -3, x = 4'], 0, '2x² - 7x - x² + 12 = 0 → x² - 7x + 12 = 0 → (x-3)(x-4) = 0 → x = 3 or x = 4.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M14', 'Math', 'Arithmetic', 'Ms. Snead''s classroom has 24 students. If 8 have pets, approximately what percent have pets?', NULL, ARRAY['33%','16%','0.33%','0.16%'], 0, '8/24 = 1/3 ≈ 33%.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M15', 'Math', 'Arithmetic', 'Carlos spends 1/8 of his monthly salary on utility bills. If utilities total $320, what is his salary?', NULL, ARRAY['$2,560','$2,440','$2,520','$2,600'], 0, 'Salary × 1/8 = $320 → Salary = $320 × 8 = $2,560.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M16', 'Math', 'Geometry', 'If the volume of a cube is 8 cm³, what is the length of the side?', NULL, ARRAY['2 cm','1 cm','3 cm','4 cm'], 0, 'Side = ∛8 = 2 cm.', 2)
