INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M17', 'Math', 'Algebra', 'Simplify: (2x² + 3)(2x - 1)', NULL, ARRAY['4x³ - 2x² + 6x - 3','2x² + 6x - 3','4x³ - 2x² + 6x + 3','4x³ - 2x² - 6x - 3'], 0, 'FOIL: 2x²·2x = 4x³, 2x²·(-1) = -2x², 3·2x = 6x, 3·(-1) = -3. Result: 4x³ - 2x² + 6x - 3.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M18', 'Math', 'Algebra', 'Simplify: (2x⁴y⁷m²z) × (5x²y³m⁸)', NULL, ARRAY['10x⁶y¹⁰m¹⁰z','10x⁶y⁹m¹⁰z','7x⁶y¹⁰m¹⁰z','10x⁵y¹⁰m¹⁰z'], 0, 'Multiply coefficients: 2×5=10. Add exponents: x⁴⁺²=x⁶, y⁷⁺³=y¹⁰, m²⁺⁸=m¹⁰, z stays. = 10x⁶y¹⁰m¹⁰z.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M19', 'Math', 'Arithmetic', 'A classroom has 13 boys and 18 girls. If a name is chosen randomly, what is the probability it''s a girl?', NULL, ARRAY['58%','42%','36%','72%'], 0, 'Total = 31. P(girl) = 18/31 ≈ 0.58 = 58%.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_M20', 'Math', 'Arithmetic', 'Ms. Marejo paid $52 for a dress from clearance. If the dress was 20% off, what was the list price?', NULL, ARRAY['$65','$260','$62.40','$41.60'], 0, '$52 = 80% of original. Original = $52/0.80 = $65.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M1', 'Math', 'Algebra', 'The expression 3x² + 3x - 18 is equal to the product of (x+3) and which other factor?', NULL, ARRAY['(3x - 6)','(3x - 4)','(3x + 4)','(3x + 6)'], 0, 'Check: (x+3)(3x-6) = 3x² - 6x + 9x - 18 = 3x² + 3x - 18. ✓', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M2', 'Math', 'Algebra', 'If 10x + 2 = 7, what is the value of 2x?', NULL, ARRAY['1','0.5','-0.5','5'], 0, '10x = 5 → x = 0.5 → 2x = 1.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M3', 'Math', 'Word Problems', 'Quinn deposits $250 from each quarterly paycheck into savings. How much after 5 years?', NULL, ARRAY['$5,000','$4,800','$5,200','$5,400'], 0, 'Quarterly = 4 times/year. 5 years × 4 = 20 deposits. 20 × $250 = $5,000.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M4', 'Math', 'Word Problems', 'Vivian has $50. She buys a calculator, then a book costing half the calculator, then a pen costing half the book. She has $15 left. How much was the calculator?', NULL, ARRAY['$20','$14','$15','$18'], 0, 'Let calc = c. Book = c/2. Pen = c/4. Total: c + c/2 + c/4 = 7c/4 = $35. c = $20.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M5', 'Math', 'Geometry', 'Determine the volume of a rectangular box with length 5 in, height 7 in, width 9 in.', NULL, ARRAY['315 in³','445 in³','45 in³','35 in³'], 0, 'V = 5 × 7 × 9 = 315 in³.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M6', 'Math', 'Arithmetic', 'A magician has 2 rabbits (black and white). He''s pulled the black one 16 times in a row. What is the probability of pulling white next?', NULL, ARRAY['0.5','1','1/17','0'], 0, 'Each draw is independent. P(white) = 1/2 = 0.5 regardless of previous draws (gambler''s fallacy).', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M7', 'Math', 'Word Problems', 'Plan A: $25/month + 5¢/min. Plan B: $50/month unlimited. At what duration are they equal?', NULL, ARRAY['8 hours and 20 minutes','500 hours','8 hours and 33 minutes','5 hours'], 0, '25 + 0.05x = 50 → 0.05x = 25 → x = 500 minutes = 8 hrs 20 min.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M8', 'Math', 'Algebra', 'What is 4⁶ ÷ 2⁸?', NULL, ARRAY['16','2','8','32'], 0, '4⁶ = (2²)⁶ = 2¹². 2¹² ÷ 2⁸ = 2⁴ = 16.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M9', 'Math', 'Geometry', 'AC and BD are straight lines intersecting at E. Angle BEC is 45°. What is angle AEB?', NULL, ARRAY['135°','90°','115°','180°'], 0, 'AEB and BEC are supplementary (they form a straight line AC). 180° - 45° = 135°.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M10', 'Math', 'Geometry', 'A circle has an area equal to 36π. What is its diameter?', NULL, ARRAY['12','6','4','4π'], 0, 'A = πr² = 36π → r² = 36 → r = 6 → diameter = 12.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC1', 'Mechanical', 'Kinematics', 'A cannon fires a projectile toward mountains. Neglecting air resistance, where is the velocity greatest?', NULL, ARRAY['Exiting the muzzle','Halfway to the mountains','As it impacts the mountains'], 0, 'Velocity is greatest at launch. Gravity decelerates the projectile on the way up and re-accelerates on the way down, but never exceeds initial velocity without additional force.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC2', 'Mechanical', 'Fluids', 'The larger piston has 4× the area of the smaller piston. If the small piston is compressed 8 inches, how far will the larger piston move?', NULL, ARRAY['2 inches','8 inches','32 inches'], 0, 'Volume is conserved. A₁×d₁ = A₂×d₂. Since A₂ = 4A₁: d₂ = d₁/4 = 8/4 = 2 inches.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC3', 'Mechanical', 'Energy', 'A pendulum swings once per second. Shortened by removing half the string, new frequency is 1.4 Hz. How many swings per minute?', NULL, ARRAY['84 times','92 times','72 times'], 0, '1.4 Hz = 1.4 swings/second. Per minute: 1.4 × 60 = 84 times.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC4', 'Mechanical', 'Fluids', 'Two identical pistons are connected by a pipe. What is the mechanical advantage?', NULL, ARRAY['1','0.5','2'], 0, 'MA = A₂/A₁. Since they''re identical, A₂ = A₁, so MA = 1.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC5', 'Mechanical', 'Kinematics', 'A ball thrown horizontally off a cliff and an identical ball dropped at the same time. How long after the dropped ball hits will the thrown ball hit?', NULL, ARRAY['At the same time','Approximately 1 second after','Approximately 2 seconds after'], 0, 'Horizontal velocity doesn''t affect vertical fall time. Both experience same gravitational acceleration, so they hit at the same time.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC6', 'Mechanical', 'Levers', 'Which is NOT a way to increase torque applied to a wrench?', NULL, ARRAY['Angling the force toward the center','Increasing the length from center to applied force','Increasing the force'], 0, 'Torque = F × d × sin(θ). Angling toward the center (θ→0) reduces the perpendicular component, decreasing torque.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC7', 'Mechanical', 'Energy', 'A ball is pushed into a vertical spring then released upward. Which describes the energy states?', NULL, ARRAY['Potential energy to kinetic energy','Convective energy to potential energy','Kinetic energy to potential energy'], 0, 'Compressed spring = elastic PE. When released, PE converts to KE as the ball moves upward.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

