VALUES ('MPT1_MC8', 'Mechanical', 'Fluids', 'A vacuum tank at 50 feet underwater is raised to 25 feet. Will the pressure on the walls increase, decrease, or stay the same?', NULL, ARRAY['Decrease','Increase','Stay the same'], 0, 'Water pressure increases with depth. Moving from 50ft to 25ft means less water above = less pressure on the tank walls.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC9', 'Mechanical', 'Electricity', 'Which electrical component holds a voltage across a gap between two conductive materials?', NULL, ARRAY['Capacitor','Resistor','Inductor'], 0, 'A capacitor stores energy in an electric field between two parallel plates (conductive materials separated by a gap).', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT1_MC10', 'Mechanical', 'Energy', 'A ball thrown straight up has initial KE of 100 ft-lbs. What is PE at half the max height?', NULL, ARRAY['50 foot-pounds','33 foot-pounds','66 foot-pounds'], 0, 'At half height, half the KE has converted to PE. So PE = 50 ft-lbs, remaining KE = 50 ft-lbs.', 2)
