INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M11', 'Math', 'Word Problems', 'Mike is at a salad bar costing 15 cents per ounce. He has 1/4 lb blueberries, 1/2 lb strawberries, 1/2 lb yogurt, 1/4 lb walnuts. How much will it cost?', NULL, ARRAY['$3.60','$1.80','$2.75','$3.00'], 0, 'Total weight = 0.25+0.5+0.5+0.25 = 1.5 lbs = 24 oz. Cost = 24 × $0.15 = $3.60.', 2)
