INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M16', 'Math', 'Word Problems', 'Morris works 7AM to 4:30PM. He earns $12/hr for 8 hours and 50% more for overtime. How much did he make?', NULL, ARRAY['$123','$134','$106','$89'], 0, 'Regular: 8 × $12 = $96. OT: 1.5 hrs × $18 = $27. Total = $96 + $27 = $123.', 2)
