INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M17', 'Math', 'Algebra', 'Mandy buys 4 yogurts + 3 crackers for $9.55, and 2 yogurts + 2 crackers for $5.90. How much does one box of crackers cost?', NULL, ARRAY['$1.75','$2.00','$2.25','$2.50'], 2, 'System: 4y+3c=9.55, y+c=2.95. Substituting: 4(2.95-c)+3c=9.55 → 11.80-4c+3c=9.55 → c=$2.25.', 2)
ON CONFLICT (id) DO UPDATE SET question_text = EXCLUDED.question_text, explanation = EXCLUDED.explanation;

INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M18', 'Math', 'Geometry', 'What is the distance from (0,-5) to (-4,6)?', NULL, ARRAY['√137','√17','√153','√223'], 0, 'd = √((-4-0)² + (6-(-5))²) = √(16+121) = √137.', 2)
