INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_M19', 'Math', 'Arithmetic', 'What is √6 between?', NULL, ARRAY['2 and 3','0 and 1','1 and 2','3 and 4'], 0, '2² = 4 and 3² = 9. Since 4 < 6 < 9, √6 is between 2 and 3.', 2)
