VALUES ('MPT2_M20', 'Math', 'Arithmetic', 'If x/8 = y/4 = 4, what is x - y?', NULL, ARRAY['16','8','32','48'], 0, 'x/8 = 4 → x = 32. y/4 = 4 → y = 16. x - y = 32 - 16 = 16.', 2)
