VALUES ('MPT3_M1', 'Math', 'Word Problems', 'A 24-foot building casts a 6-foot shadow. A dog nearby casts a 0.75-foot shadow. How tall is the dog?', NULL, ARRAY['3 feet','1.5 feet','2 feet','2.5 feet'], 0, '24/6 = dog/0.75. dog = 24×0.75/6 = 3 feet.', 2)
