VALUES ('MPT3_M3', 'Math', 'Word Problems', 'Gillian''s Plan A: 2.5GB for $20 + $15/extra GB. Plan B: $50 unlimited. At what usage are they equal?', NULL, ARRAY['4.5 GB','2 GB','3.5 GB','3.75 GB'], 0, '20 + 15(x-2.5) = 50 → 15x - 37.5 = 30 → 15x = 67.5 → x = 4.5 GB.', 2)
