VALUES ('MPT3_M4', 'Math', 'Geometry', 'A room is 12ft long, 9ft high, 10ft wide. How many sq ft to paint (walls, floor, ceiling)?', NULL, ARRAY['636','425','898','1080'], 0, '2(12×9) + 2(10×9) + 2(12×10) = 216 + 180 + 240 = 636 sq ft.', 2)
