VALUES ('MPT3_M5', 'Math', 'Algebra', 'A rectangle is twice as long as it is wide. If it were 3in shorter and 3in wider, it''d be a square. What is the width?', NULL, ARRAY['6','4','8','12'], 0, 'L=2W. L-3 = W+3 → 2W-3 = W+3 → W = 6.', 2)
