VALUES ('MPT2_MC3', 'Mechanical', 'Fluids', 'Water flows through a funnel. Compared to the large end, does the small end have greater, lower, or same water speed?', NULL, ARRAY['Greater water speed','Lower water speed','Same water speed'], 0, 'Continuity equation: A₁v₁ = A₂v₂. Smaller area = faster speed.', 2)
