INSERT INTO questions (id, section, topic, question_text, passage, options, correct_index, explanation, difficulty)
VALUES ('MPT2_MC4', 'Mechanical', 'Energy', 'A soccer ball is kicked up. Ignoring air resistance, when it hits the ground will it be going slower, faster, or the same speed as when kicked?', NULL, ARRAY['Same speed','Slower','Faster'], 0, 'Conservation of energy: all KE converts to PE then back to KE. Same speed at same height (ignoring air resistance).', 2)
